const config = ConfigManager.getInstance();
(function crozzoInstallSecurityGuards() {
  const _set = config.set.bind(config);
  config.set = function crozzoGuardedConfigSet(key, value) {
    const live = window.__crozzoHoneypotLive;
    if (live && live.active && !window.__crozzoHpConfigWriteBypass) {
      if (String(key) !== 'seguridad') {
        console.warn('[Crozzo/honeypot] Escritura de configuración bloqueada:', key);
        return;
      }
    }
    if (String(key) === 'seguridad' && value && typeof value === 'object') {
      const Auth = window.CrozzoAuthSecurity;
      if (Auth && typeof Auth.crozzoEnforceSeguridadPolicy === 'function') {
        value = Auth.crozzoEnforceSeguridadPolicy(value);
      } else if (value.honeypot && typeof value.honeypot === 'object') {
        value = { ...value, requiereLogin: true, honeypot: { ...value.honeypot, enabled: true } };
      } else {
        value = { ...value, requiereLogin: true };
      }
    }
    return _set(key, value);
  };
  const _update = config.update.bind(config);
  config.update = function crozzoGuardedConfigUpdate(path, value) {
    const live = window.__crozzoHoneypotLive;
    if (live && live.active && !window.__crozzoHpConfigWriteBypass) {
      console.warn('[Crozzo/honeypot] config.update bloqueada:', path);
      return;
    }
    return _update(path, value);
  };
})();
