function crozzoHpLiveResolveCart(live, ctx) {
  if (!live) return (ctx && ctx.sampleCart) || [];
  if (!Array.isArray(live.cart) || !live.cart.length) {
    const Sim = window.CrozzoHoneypotSim;
    const catalog = (ctx && ctx.catalog) || [];
    live.cart =
      Sim && typeof Sim.buildSampleCart === 'function'
        ? Sim.buildSampleCart(catalog)
        : (ctx && ctx.sampleCart) || [];
  }
  return live.cart;
}
function crozzoHpLiveTapProduct(productId) {
  const live = window.__crozzoHoneypotLive;
  if (!live || !live.active || !live.ctx) return;
  const p = (live.ctx.catalog || []).find(function (x) {
    return String(x.id) === String(productId);
  });
  if (!p) return;
  if (!Array.isArray(live.cart)) live.cart = [];
  const row = live.cart.find(function (i) {
    return i.id === p.id;
  });
  if (row) row.cantidad++;
  else live.cart.push({ id: p.id, nombre: p.nombre, precio: p.precio, icon: p.icon || '🍽️', cantidad: 1 });
  if (typeof renderPage === 'function') renderPage(typeof currentPage !== 'undefined' ? currentPage : 'cajero');
  if (typeof showToast === 'function') showToast(p.nombre + ' agregado al pedido', 'success');
}
function crozzoHpLiveSelectMesa(mesaId) {
  const live = window.__crozzoHoneypotLive;
  if (!live || !live.active) return;
  live.selectedMesa = mesaId;
  live.cajaMode = 'mesa';
  if (typeof showToast === 'function') showToast('Mesa ' + mesaId + ' seleccionada', 'info');
  if (typeof renderPage === 'function') renderPage('cajero');
}
function crozzoHpLiveCobrar() {
  const live = window.__crozzoHoneypotLive;
  if (!live || !live.active) return;
  const cart = crozzoHpLiveResolveCart(live, live.ctx);
  if (!cart.length) {
    if (typeof showToast === 'function') showToast('Agregue productos antes de cobrar', 'warning');
    return;
  }
  const total = cart.reduce(function (s, i) {
    return s + i.precio * i.cantidad;
  }, 0);
  if (typeof showToast === 'function') showToast('Procesando pago · $' + total.toLocaleString('es-CO') + '…', 'info');
  setTimeout(function () {
    if (typeof showToast === 'function') {
      showToast('✅ Venta registrada · comanda enviada a cocina', 'success');
    }
    const Sim = window.CrozzoHoneypotSim;
    if (Sim && typeof Sim.buildSampleCart === 'function' && live.ctx) {
      live.cart = Sim.buildSampleCart(live.ctx.catalog || []);
    }
    if (typeof renderPage === 'function') renderPage(typeof currentPage !== 'undefined' ? currentPage : 'cajero');
  }, 900);
}
