function crozzoOpenForcePasswordChangeModal(user) {
  const ov = document.getElementById('crozzoForcePasswordOverlay');
  if (!ov) return;
  ov.dataset.userId = user && user.id ? user.id : '';
  const sub = document.getElementById('forcePasswordSubtitle');
  if (sub) {
    sub.textContent =
      user && user.id === 'KENNY'
        ? 'Por seguridad debe cambiar la contraseña de fábrica del Super Admin en este PC.'
        : 'Su contraseña es débil o antigua. Defina una nueva para continuar.';
  }
  ['forcePasswordNew', 'forcePasswordConfirm'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.value = '';
  });
  const err = document.getElementById('forcePasswordError');
  if (err) { err.hidden = true; err.textContent = ''; }
  ov.removeAttribute('hidden');
  document.body.style.overflow = 'hidden';
  const neu = document.getElementById('forcePasswordNew');
  if (neu) neu.focus();
}
function crozzoCloseForcePasswordChangeModal() {
  const ov = document.getElementById('crozzoForcePasswordOverlay');
  if (ov) ov.setAttribute('hidden', '');
  document.body.style.overflow = '';
}
async function crozzoSubmitForcePasswordChange() {
  const Auth = window.CrozzoAuthSecurity;
  const errEl = document.getElementById('forcePasswordError');
  const showFpErr = msg => {
    if (errEl) { errEl.textContent = msg; errEl.hidden = false; }
  };
  const ov = document.getElementById('crozzoForcePasswordOverlay');
  const userId = ov && ov.dataset.userId;
  const neu = (document.getElementById('forcePasswordNew')?.value || '').trim();
  const conf = (document.getElementById('forcePasswordConfirm')?.value || '').trim();
  if (!userId) return showFpErr('Sesión inválida. Vuelva a iniciar sesión.');
  if (!neu || neu !== conf) return showFpErr('La confirmación no coincide.');
  if (Auth && typeof Auth.crozzoPasswordPolicy === 'function') {
    const pol = Auth.crozzoPasswordPolicy(neu, userId);
    if (!pol.ok) return showFpErr(pol.msg);
  } else if (neu.length < 8) {
    return showFpErr('Mínimo 8 caracteres.');
  }
  const staff = getUsuariosConfig().staff || [];
  const u = staff.find(s => s.id === userId);
  if (!u) return showFpErr('Usuario no encontrado.');
  try {
    let next = u;
    if (Auth && typeof Auth.crozzoApplyPasswordToUser === 'function') {
      next = await Auth.crozzoApplyPasswordToUser(u, neu);
    } else {
      next = { ...u, clave: neu };
    }
    const nextStaff = staff.map(s => (s.id === userId ? next : s));
    saveUsuarios(nextStaff);
    const seg = config.get('seguridad') || {};
    if (userId === 'KENNY') {
      config.set('seguridad', { ...seg, kennyPasswordChanged: true, requiereLogin: true });
    }
    config.addAudit('password_cambiada_obligatoria', `Usuario ${userId} actualizó contraseña (política)`);
    crozzoCloseForcePasswordChangeModal();
    applyAccessControl();
    if (typeof window.__crozzoPostInitCloud === 'function') {
      try { await window.__crozzoPostInitCloud(); } catch (_) {}
    }
    crozzoDispatchAuthReady({ source: 'password-change' });
    navigateTo(typeof pickFirstAccessiblePage === 'function' ? pickFirstAccessiblePage() || 'cajero' : 'cajero');
    showToast('Contraseña actualizada. Ya puede usar el sistema.', 'success');
    try {
      if (window.CrozzoA11yUser && typeof CrozzoA11yUser.syncUserMenuProfile === 'function') {
        CrozzoA11yUser.syncUserMenuProfile();
      }
    } catch (_) {}
  } catch (e) {
    showFpErr(String(e && e.message ? e.message : e) || 'No se pudo guardar.');
  }
}
function crozzoCancelForcePasswordChange() {
  crozzoCloseForcePasswordChangeModal();
  logoutCurrentUser();
  applyAccessControl();
  showLoginOverlay();
  showToast('Debe definir una contraseña segura para continuar.', 'warning');
}
window.crozzoOpenForcePasswordChangeModal = crozzoOpenForcePasswordChangeModal;
window.crozzoSubmitForcePasswordChange = crozzoSubmitForcePasswordChange;
window.crozzoCancelForcePasswordChange = crozzoCancelForcePasswordChange;
var __crozzoSessionIdleTimer = null;
var __crozzoLastActivityTs = Date.now();
function crozzoTouchActivity() {
  __crozzoLastActivityTs = Date.now();
}
function crozzoInitSessionIdleWatch() {
  if (__crozzoSessionIdleTimer) {
    clearInterval(__crozzoSessionIdleTimer);
    __crozzoSessionIdleTimer = null;
  }
  const seg = config.get('seguridad') || {};
  const mins = typeof seg.sessionIdleMinutes === 'number' ? seg.sessionIdleMinutes : 30;
  if (!mins || mins <= 0) return;
  if (!window.__crozzoActivityBound) {
    window.__crozzoActivityBound = true;
    ['mousedown', 'keydown', 'touchstart', 'scroll'].forEach(ev => {
      document.addEventListener(ev, crozzoTouchActivity, { passive: true, capture: true });
    });
  }
  __crozzoLastActivityTs = Date.now();
  __crozzoSessionIdleTimer = setInterval(() => {
    try {
      if (typeof crozzoKioskComandasEffective === 'function' && crozzoKioskComandasEffective()) return;
      if (typeof getCurrentUser !== 'function' || !getCurrentUser()) return;
      if (typeof crozzoShiftLoginBlocking === 'function' && crozzoShiftLoginBlocking()) return;
      const ov = document.getElementById('crozzoForcePasswordOverlay');
      if (ov && !ov.hasAttribute('hidden')) return;
      const idleMs = mins * 60 * 1000;
      if (Date.now() - __crozzoLastActivityTs < idleMs) return;
      logoutCurrentUser();
      applyAccessControl();
      if (shouldRequireLogin()) showLoginOverlay();
      showToast(`Sesión cerrada por inactividad (${mins} min)`, 'info');
    } catch (e) {
      console.warn('[auth] idle', e);
    }
  }, 30000);
}
window.crozzoInitSessionIdleWatch = crozzoInitSessionIdleWatch;
// Aplica el rolPredeterminado del usuario al config.conexionSistemas.
// Pide confirmación si difiere del rol actual del dispositivo.
function applyDeviceRoleFromUser(userId) {
  const u = (getUsuariosConfig().staff || []).find(s => s.id === userId);
  if (!u) return { ok: false, error: 'usuario_no_encontrado' };
  const cd = u.configDispositivo || {};
  const target = cd.rolPredeterminado || 'auto';
  if (target === 'auto') return { ok: true, applied: false, reason: 'rol_auto' };
  const actual = (config.get('conexionSistemas') || {}).role || 'A';
  if (target === actual) return { ok: true, applied: false, reason: 'rol_igual' };
  if (cd.autoAplicar === false) return { ok: true, applied: false, reason: 'auto_aplicar_off' };
  const msg = `👋 ${u.nombre}: este dispositivo se configurará como ${target === 'A' ? '🖥️ Central (A)' : '📱 Tablet (B)'}. ¿Aplicar?`;
  if (!confirm(msg)) {
    showToast('Cambio de rol cancelado', 'info');
    return { ok: true, applied: false, reason: 'cancelado_por_usuario' };
  }
  // Mezcla con la config actual sin perder IPs/puertos guardados.
  const prev = config.get('conexionSistemas') || getConexionSistemasDefaults();
  const next = { ...getConexionSistemasDefaults(), ...prev, role: target, deviceId: ensureCrozzoDeviceId() };
  config.set('conexionSistemas', next);
  // Replica al "puente" del entry point (sistema conexiones.html) y al runtime global.
  const payload = buildCrozzoConfigPayload();
  persistConexionSistemasToLegacyLocalStorage(payload);
  refreshWindowCrozzoConfigFromStorage();
  // Reinicia CrozzoSyncRouter con el nuevo perfil.
  destroyCrozzoSyncRouter();
  crozzoSyncRouter = new CrozzoSyncRouter(payload);
  crozzoSyncRouter.on('itemSynced', (item) => showToast(`Sincronizado: ${item.type}`, 'success'));
  // Replica estructura para Supabase (tabla devices) si hay credenciales.
  pushDeviceProfileToCloud(u, payload).catch(() => {});
  config.addAudit('dispositivo_rol_aplicado', `Usuario ${u.nombre} → rol ${target}`);
  showToast(`Dispositivo configurado como ${target === 'A' ? '🖥️ Central' : '📱 Tablet'} (perfil ${u.nombre})`, 'success');
  if (currentPage === 'config-conexiones-sistemas') renderPage('config-conexiones-sistemas');
  return { ok: true, applied: true, role: target };
}
// Replica el "perfil de este dispositivo" en Supabase para recuperación posterior.
async function pushDeviceProfileToCloud(user, conexionPayload) {
  const md = config.get('multidispositivo') || {};
  const sb = md.supabase || {};
  const akPush = crozzoSupabaseEffectiveAnonKey(sb) || String(sb.anonKey || '').trim();
  if (!sb.url || !akPush) return false;
  const base = String(sb.url).replace(/\/$/, '');
  const primaryTable = md.deviceConfigsTable || sb.deviceConfigsTable || 'device_configs';
  const bid = String(md.businessId || (config.get('multidispositivo') || {}).businessId || '').trim();
  const coreBody = {
    device_id: ensureCrozzoDeviceId(),
    role: conexionPayload.role || 'A',
    server_ip: conexionPayload.serverIp || null,
    central_ip: conexionPayload.centralIp || null,
    port: conexionPayload.port || 3000,
    config_json: {
      conexionSistemas: config.get('conexionSistemas'),
      configDispositivo: user?.configDispositivo || null,
      lastUserId: user?.id || null,
    },
    last_seen: new Date().toISOString(),
  };
  const bodyVariants = bid ? [{ ...coreBody, business_id: bid }, coreBody] : [coreBody];
  const postOnce = async (table, bodyObj) => {
    const url = `${base}/rest/v1/${encodeURIComponent(table)}`;
    const controller = new AbortController();
    const t = setTimeout(() => controller.abort(), 6000);
    const ak = akPush;
    try {
      const res = await fetch(url, {
        method: 'POST',
        signal: controller.signal,
        headers: {
          'apikey': ak,
          'Authorization': 'Bearer ' + ak,
          'Content-Type': 'application/json',
          Prefer: 'resolution=merge-duplicates,return=minimal',
        },
        body: JSON.stringify(bodyObj),
      });
      clearTimeout(t);
      if (res && res.status === 401) crozzoNotifySupabase401Once();
      return res;
    } catch (e) {
      clearTimeout(t);
      try {
        console.warn(e && e.message ? e.message : e);
      } catch (_) {}
      return new Response(null, { status: 503 });
    }
  };
  const tryTableWithBodies = async (table) => {
    let lastRes = null;
    for (const body of bodyVariants) {
      const res = await postOnce(table, body);
      lastRes = res;
      if (res.ok || res.status === 201 || res.status === 204) return res;
      if (res.status === 404) return res;
      if (res.status === 400 && bid) {
        try {
          const txt = await res.clone().text();
          if (/business_id|PGRST204|schema cache|Could not find|column/i.test(txt)) continue;
        } catch (_) {}
      }
      return res;
    }
    return lastRes;
  };
  try {
    let res = await tryTableWithBodies(primaryTable);
    if (res.status === 404) {
      console.warn('[crozzo-sb] device_configs no encontrada, reintento en devices');
      res = await tryTableWithBodies('devices');
    }
    if (res.ok || res.status === 201 || res.status === 204) return true;
    try {
      localStorage.setItem(
        'crozzo_device_profile_cloud_mirror',
        JSON.stringify({ savedAt: Date.now(), status: res.status, body: bodyVariants[0] })
      );
    } catch (_) {}
    return false;
  } catch (e) {
    try {
      console.warn(e && e.message ? e.message : e);
    } catch (_) {}
    try {
      localStorage.setItem('crozzo_device_profile_cloud_mirror', JSON.stringify({ savedAt: Date.now(), error: String(e), body: bodyVariants[0] }));
    } catch (_) {}
    return false;
  }
}
// Si localStorage perdió la config (cache borrado), intenta restaurarla
// desde Supabase consultando por device_id.
async function restoreConexionFromCloudIfNeeded() {
  const cs = config.get('conexionSistemas') || {};
  // Considera "configurado" si ya hay rol e IP correspondiente.
  const yaConfigurado = !!(cs.serverIp || cs.centralIp);
  if (yaConfigurado) return false;
  const md = config.get('multidispositivo') || {};
  const sb = md.supabase || {};
  const rk = crozzoSupabaseEffectiveAnonKey(sb) || String(sb.anonKey || '').trim();
  if (!sb.url || !rk) return false;
  const base = String(sb.url).replace(/\/$/, '');
  const primaryTable = md.deviceConfigsTable || sb.deviceConfigsTable || 'device_configs';
  const deviceIdText = ensureCrozzoDeviceId();
  const deviceUuid =
    typeof crozzoCloudDeviceUuidForRest === 'function' ? crozzoCloudDeviceUuidForRest() : '';
  const sbHdr = {
    'apikey': rk,
    'Authorization': 'Bearer ' + rk,
    'Content-Type': 'application/json',
  };
  const buildUrl = (tbl) => {
    if (tbl === 'devices') {
      if (!deviceUuid) return `${base}/rest/v1/devices?limit=0`;
      return `${base}/rest/v1/${encodeURIComponent(tbl)}?id=eq.${encodeURIComponent(deviceUuid)}&select=*&limit=1`;
    }
    return `${base}/rest/v1/${encodeURIComponent(tbl)}?device_id=eq.${encodeURIComponent(deviceIdText)}&select=*&limit=1`;
  };
  try {
    const controller = new AbortController();
    const t = setTimeout(() => controller.abort(), 6000);
    let res = await fetch(buildUrl(primaryTable), {
      method: 'GET',
      signal: controller.signal,
      headers: sbHdr,
    });
    if (res.status === 404) {
      if (!window.__crozzoRestore404Logged) {
        window.__crozzoRestore404Logged = true;
        console.warn('[crozzo-sb] restore: tabla device_configs no encontrada (404), probando devices');
      }
      res = await fetch(buildUrl('devices'), {
        method: 'GET',
        signal: controller.signal,
        headers: sbHdr,
      });
    }
    clearTimeout(t);
    if (res && res.status === 401) crozzoNotifySupabase401Once();
    if (!res.ok) {
      try {
        const raw = localStorage.getItem('crozzo_device_profile_cloud_mirror');
        const o = raw ? JSON.parse(raw) : null;
        if (o && o.body && o.body.config_json && o.body.config_json.conexionSistemas) {
          const r = o.body;
          const remoteCfg = r.config_json.conexionSistemas;
          const merged = {
            ...getConexionSistemasDefaults(),
            ...(remoteCfg || {}),
            role: r.role || (remoteCfg && remoteCfg.role) || 'A',
            serverIp: r.server_ip || (remoteCfg && remoteCfg.serverIp) || '',
            centralIp: r.central_ip || (remoteCfg && remoteCfg.centralIp) || '',
            port: Number(r.port) || (remoteCfg && remoteCfg.port) || 3000,
            deviceId: deviceIdText,
          };
          config.set('conexionSistemas', merged);
          refreshWindowCrozzoConfigFromStorage();
          showToast('Configuración restaurada desde copia local (mirror)', 'info');
          return true;
        }
      } catch (_) {}
      return false;
    }
    const rows = await res.json();
    if (!Array.isArray(rows) || !rows.length) return false;
    const r = rows[0];
    const remoteCfg = (r.config_json && r.config_json.conexionSistemas) || null;
    const merged = {
      ...getConexionSistemasDefaults(),
      ...(remoteCfg || {}),
      role: r.role || (remoteCfg && remoteCfg.role) || 'A',
      serverIp: r.server_ip || (remoteCfg && remoteCfg.serverIp) || '',
      centralIp: r.central_ip || (remoteCfg && remoteCfg.centralIp) || '',
      port: Number(r.port) || (remoteCfg && remoteCfg.port) || 3000,
      deviceId: deviceIdText
    };
    config.set('conexionSistemas', merged);
    // Restaura también configDispositivo del último usuario, si está disponible.
    const lastUserId = r.config_json && r.config_json.lastUserId;
    const remoteUserCD = r.config_json && r.config_json.configDispositivo;
    if (lastUserId && remoteUserCD) {
      const conf = getUsuariosConfig();
      conf.staff = conf.staff.map(u => u.id === lastUserId
        ? { ...u, configDispositivo: { ...(u.configDispositivo || {}), ...remoteUserCD } }
        : u);
      saveUsuarios(conf.staff);
    }
    refreshWindowCrozzoConfigFromStorage();
    config.addAudit('conexion_restaurada_cloud', `device_id=${deviceIdText} rol=${merged.role}`);
    showToast('Configuración del dispositivo restaurada desde Supabase', 'success');
    return true;
  } catch (e) {
    try {
      console.warn(e && e.message ? e.message : e);
    } catch (_) {}
    return false;
  }
}
