class CrozzoSyncRouter {
  constructor(cfg) {
    this.config = cfg;
    this.db = null;
    this.isConnected = false;
    this.isSyncing = false;
    this.queue = [];
    this.eventHandlers = {};
    this.retryInterval = null;
    this.heartbeatInterval = null;
    this.init().catch(() => console.warn('CrozzoSyncRouter: init parcial (IndexedDB o red)'));
  }
  async init() {
    await this.initIndexedDB();
    this.startHealthCheck();
    this.startAutoSync();
    this.loadQueue();
  }
  initIndexedDB() {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open('CrozzoSyncDB', 1);
      request.onupgradeneeded = (event) => {
        const db = event.target.result;
        if (!db.objectStoreNames.contains('syncQueue')) {
          const store = db.createObjectStore('syncQueue', { keyPath: 'uuid' });
          store.createIndex('status', 'status', { unique: false });
          store.createIndex('timestamp', 'timestamp', { unique: false });
          store.createIndex('type', 'type', { unique: false });
        }
      };
      request.onsuccess = (event) => {
        this.db = event.target.result;
        resolve();
      };
      request.onerror = (event) => reject(event);
    });
  }
  startHealthCheck() {
    const check = async () => {
      const ip = this.config.serverIp || this.config.centralIp;
      const port = this.config.port;
      if (!ip) {
        this.setConnected(false);
        return;
      }
      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 3000);
        await fetch(`http://${ip}:${port}/health`, {
          method: 'GET',
          signal: controller.signal,
          mode: 'no-cors'
        });
        clearTimeout(timeoutId);
        this.setConnected(true);
      } catch (err) {
        this.setConnected(false);
      }
    };
    check();
    this.heartbeatInterval = setInterval(check, 30000);
  }
  startAutoSync() {
    this.retryInterval = setInterval(() => {
      if (this.isConnected && this.queue.length > 0 && !this.isSyncing) this.syncQueue();
    }, 15000);
  }
  async send(operation) {
    const payload = {
      uuid: operation.uuid || crozzoUuid(),
      timestamp: Date.now(),
      deviceId: this.config.deviceId,
      type: operation.type,
      data: operation.data,
      status: 'pending',
      retries: 0
    };
    if (this.isConnected) {
      try {
        const ip = this.config.serverIp || this.config.centralIp;
        const port = this.config.port;
        const endpoint = operation.type === 'order' ? '/api/orders' : operation.type === 'sale' ? '/api/sales' : '/api/sync';
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 5000);
        await fetch(`http://${ip}:${port}${endpoint}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
          signal: controller.signal,
          mode: 'no-cors'
        });
        clearTimeout(timeoutId);
        payload.status = 'synced';
        this.emit('syncStatusChanged', { status: 'synced', uuid: payload.uuid });
        return { success: true, uuid: payload.uuid };
      } catch (err) {
        console.warn('Envío directo falló, cola offline', err);
      }
    }
    await this.saveToQueue(payload);
    this.queue.push(payload);
    this.emit('syncStatusChanged', { status: 'queued', uuid: payload.uuid });
    this.updateSyncUI();
    return { success: false, queued: true, uuid: payload.uuid };
  }
  saveToQueue(item) {
    return new Promise((resolve, reject) => {
      if (!this.db) return resolve();
      const transaction = this.db.transaction(['syncQueue'], 'readwrite');
      const store = transaction.objectStore('syncQueue');
      const request = store.put(item);
      request.onsuccess = () => resolve();
      request.onerror = (e) => reject(e);
    });
  }
  async loadQueue() {
    if (!this.db) return;
    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction(['syncQueue'], 'readonly');
      const store = transaction.objectStore('syncQueue');
      const request = store.getAll();
      request.onsuccess = () => {
        this.queue = request.result.filter((item) => item.status !== 'synced');
        this.updateSyncUI();
        resolve();
      };
      request.onerror = (e) => reject(e);
    });
  }
  async syncQueue() {
    if (this.isSyncing || !this.isConnected) return;
    this.isSyncing = true;
    const pending = this.queue.filter((item) => item.status === 'pending');
    for (const item of pending) {
      try {
        item.retries++;
        const result = await this.sendDirect(item);
        if (result.success) {
          item.status = 'synced';
          await this.saveToQueue(item);
          this.queue = this.queue.filter((q) => q.uuid !== item.uuid);
          this.emit('itemSynced', item);
        }
      } catch (err) {
        if (item.retries >= 10) {
          item.status = 'failed';
          await this.saveToQueue(item);
          this.emit('itemFailed', item);
        }
      }
    }
    this.isSyncing = false;
    this.updateSyncUI();
  }
  async sendDirect(item) {
    const ip = this.config.serverIp || this.config.centralIp;
    const port = this.config.port;
    const endpoint = item.type === 'order' ? '/api/orders' : item.type === 'sale' ? '/api/sales' : '/api/sync';
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 5000);
    await fetch(`http://${ip}:${port}${endpoint}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(item),
      signal: controller.signal,
      mode: 'no-cors'
    });
    clearTimeout(timeoutId);
    return { success: true };
  }
  on(event, callback) {
    if (!this.eventHandlers[event]) this.eventHandlers[event] = [];
    this.eventHandlers[event].push(callback);
  }
  emit(event, data) {
    if (this.eventHandlers[event]) this.eventHandlers[event].forEach((cb) => cb(data));
  }
  setConnected(connected) {
    if (this.isConnected === connected) return;
    this.isConnected = connected;
    const dot = document.getElementById('crozzoSyncDot');
    const text = document.getElementById('crozzoSyncStatusText');
    if (dot) dot.className = `crozzo-sync-dot ${connected ? 'online' : 'offline'}`;
    if (text) text.textContent = connected ? 'Conectado al servidor LAN' : 'Sin servidor / modo cola local';
    if (connected) this.syncQueue();
  }
  updateSyncUI() {
    const count = this.queue.filter((q) => q.status === 'pending').length;
    const el = document.getElementById('crozzoSyncQueueCount');
    if (el) el.textContent = String(count);
  }
  destroy() {
    if (this.heartbeatInterval) clearInterval(this.heartbeatInterval);
    if (this.retryInterval) clearInterval(this.retryInterval);
    if (this.db) this.db.close();
    this.db = null;
  }
}
function destroyCrozzoSyncRouter() {
  if (crozzoSyncRouter) {
    crozzoSyncRouter.destroy();
    crozzoSyncRouter = null;
  }
}
window.CrozzoSyncRouter = CrozzoSyncRouter;
window.crozzoSyncSend = function (operation) {
  if (crozzoSyncRouter) return crozzoSyncRouter.send(operation);
  return Promise.resolve({ success: false, queued: false, error: 'SyncRouter no activo (abre Admin → Conexión de sistemas)' });
};
