const CROZZO_SIDEBAR_NAV_LS = 'crozzo_menu_state';
function crozzoSaveSidebarNavState() {
  if (window.CrozzoSidebarNav && typeof CrozzoSidebarNav.save === 'function') {
    CrozzoSidebarNav.save();
    return;
  }
  try {
    const state = { groups: {}, pinned: false };
    document.querySelectorAll('#sidebarNav .nav-group[data-nav-group], #sidebarNav .nav-group-li[data-group]').forEach(function (g) {
      const id = g.dataset.navGroup || g.dataset.group;
      if (!id) return;
      state.groups[id] = g.classList.contains('open');
    });
    localStorage.setItem(CROZZO_SIDEBAR_NAV_LS, JSON.stringify(state));
  } catch (e) {
    console.warn('[nav] save', e);
  }
}
function crozzoRestoreSidebarNavState() {
  if (window.CrozzoSidebarNav && typeof CrozzoSidebarNav.restore === 'function') {
    CrozzoSidebarNav.restore(false);
    try {
      if (typeof initMobileUX === 'function') initMobileUX();
    } catch (_) {}
    return;
  }
  try {
    const raw = localStorage.getItem(CROZZO_SIDEBAR_NAV_LS);
    if (!raw) return;
    const state = JSON.parse(raw);
    const groups = state.groups || state;
    if (!groups || typeof groups !== 'object') return;
    document.querySelectorAll('#sidebarNav .nav-group[data-nav-group], #sidebarNav .nav-group-li[data-group]').forEach(function (g) {
      const id = g.dataset.navGroup || g.dataset.group;
      if (!id || groups[id] === undefined) return;
      const open = typeof groups[id] === 'boolean' ? groups[id] : !groups[id];
      g.classList.toggle('open', open);
      g.classList.toggle('nav-group-collapsed', !open);
      const btn = g.querySelector('.nav-group-toggle');
      if (btn) btn.setAttribute('aria-expanded', open ? 'true' : 'false');
      const sub = g.querySelector('.nav-group-items');
      if (sub) sub.classList.toggle('open', open);
    });
    try {
      if (typeof initMobileUX === 'function') initMobileUX();
    } catch (_) {}
  } catch (e) {
    console.warn('[nav] restore', e);
  }
}
function expandNavGroupForPage(page) {
  if (window.CrozzoSidebarNav && typeof CrozzoSidebarNav.expandGroupForPage === 'function') {
    CrozzoSidebarNav.expandGroupForPage(page);
    return;
  }
  document.querySelectorAll('.nav-group, .nav-group-li').forEach(group => {
    const match = group.querySelector(`.nav-item[data-page="${page}"]`);
    if (!match) return;
    group.classList.remove('nav-group-collapsed');
    group.classList.add('open');
    const btn = group.querySelector('.nav-group-toggle');
    if (btn) btn.setAttribute('aria-expanded', 'true');
    const sub = group.querySelector('.nav-group-items');
    if (sub) sub.classList.add('open');
  });
  crozzoSaveSidebarNavState();
}
