function crozzoApplyVisualTheme(themeId) {
  var t = String(themeId || '').toLowerCase().trim();
  if (CROZZO_THEME_IDS.indexOf(t) < 0) t = 'executive-elite';
  document.documentElement.setAttribute('data-theme', t);
  if (CROZZO_THEME_LIGHT.indexOf(t) >= 0) {
    document.documentElement.style.colorScheme = 'light';
  } else if (CROZZO_THEME_DARK.indexOf(t) >= 0) {
    document.documentElement.style.colorScheme = 'dark';
  } else {
    document.documentElement.style.removeProperty('color-scheme');
  }
  if (document.body) {
    document.body.classList.toggle('crozzo-theme-light', CROZZO_THEME_LIGHT.indexOf(t) >= 0);
    document.body.classList.toggle('crozzo-theme-dark', CROZZO_THEME_DARK.indexOf(t) >= 0);
  }
  try {
    localStorage.setItem(CROZZO_THEME_LS_KEY, t);
    if (CROZZO_THEME_CLASSIC.indexOf(t) >= 0) {
      localStorage.setItem(CROZZO_THEME_LEGACY_LS_KEY, t);
    }
  } catch (e) {
    /* ignore */
  }
  var sel = document.getElementById('crozzoThemeSelect');
  if (sel && sel.value !== t) sel.value = t;
  crozzoBroadcastThemeToEmbeds(t);
  try {
    if (global.CrozzoBonaOrigen && typeof global.CrozzoBonaOrigen.onThemeChange === 'function') {
      global.CrozzoBonaOrigen.onThemeChange(t);
    }
  } catch (_) {}
}
