// INVENTARIOS / PRODUCTOS (placeholders)
// ==========================================
function renderTablets() {
  const tabCanEditQty = crozzoHasCajaPermiso('editar_orden', { context: 'tablet' });
  const tabCanClearOrder = crozzoHasCajaPermiso('eliminar_item', { context: 'tablet' });
  const pedidoTarget = tabletModoPedido === 'mesa'
    ? mesasCaja.find(m => m.id === tabletMesaSeleccionada)
    : llevarCaja.find(l => l.id === tabletLlevarSeleccionado);
  const cart = getTabletActiveCart();
  const totals = computeTotals(cart);
  const tabLabSub = totals.ivaIncluidoEnPrecios ? 'Neto sin impuesto' : 'Subtotal';
  const tabLabIva = totals.ivaIncluidoEnPrecios ? 'Impuesto' : 'IVA / impuesto';
  if (!tabletOrderOpen) {
    return `
      <div class="card">
        <div class="card-header">
          <div>
            <h2 class="card-title">Tablets - Toma de pedidos</h2>
            <p class="page-subtitle" style="margin-top:4px;">Selecciona ${tabletModoPedido === 'mesa' ? 'mesa' : 'pedido de llevar'} para abrir pedido</p>
          </div>
        </div>
        <div class="service-mode-switch">
          <button class="service-mode-btn ${tabletModoPedido === 'mesa' ? 'active' : ''}" onclick="setTabletMode('mesa')">🍽️ Mesas salón</button>
          <button class="service-mode-btn ${tabletModoPedido === 'llevar' ? 'active' : ''}" onclick="setTabletMode('llevar')">🥡 Pedidos de llevar</button>
        </div>
        <div style="margin-bottom: 12px;">
          <input type="text" class="form-input" id="tabletSearchTarget" placeholder="🔎 Buscar ${tabletModoPedido === 'mesa' ? 'mesa' : 'pedido llevar'}..." value="${tabletTargetSearch}">
        </div>
        <div class="mesas-grid">
          ${(tabletModoPedido === 'mesa' ? mesasCaja : llevarCaja)
            .filter(s => normalizeText(s.nombre).includes(normalizeText(tabletTargetSearch)) || normalizeText(s.id).includes(normalizeText(tabletTargetSearch)))
            .map(s => `
            <div class="mesa-card ${getSlotCardClass(tabletModoPedido, s.id)}" onclick="${tabletModoPedido === 'mesa' ? `selectTabletMesa('${s.id}')` : `selectTabletLlevar('${s.id}')`}">
              <div class="mesa-card-name">${s.nombre}</div>
              <div class="mesa-card-status">${tabletModoPedido === 'mesa' ? getMesaStatus(s.id) : getLlevarStatus(s.id)}</div>
            </div>
          `).join('') || `<div style="grid-column:1/-1; color:var(--text-muted); padding:10px;">Sin resultados</div>`}
        </div>
      </div>
    `;
  }
  return `
    <div class="card">
      <div class="card-header">
        <div>
          <h2 class="card-title">Pedido ${pedidoTarget ? pedidoTarget.nombre : '-'}</h2>
          <p class="page-subtitle" style="margin-top:4px;">Edición rápida de pedido (tablet/celular)</p>
        </div>
        <button class="btn btn-outline" onclick="closeTabletOrderPanel()">✕ Cerrar</button>
      </div>
      <div style="display:flex; gap:8px; margin-bottom: 12px;">
        <input type="text" class="form-input" id="tabletSearchProduct" placeholder="🔎 Buscar producto, código o SKU…" style="flex:1;" title="Atajos: Ctrl+K buscar · Ctrl+Enter confirmar pedido" autocomplete="off">
      </div>
      <div class="tablet-layout crozzo-tablet-touch">
        <div class="pos-products" id="tabletProducts">
          ${products.map(p => `
            <div class="product-card" onclick="tabletAddToCart(${p.id})" data-name="${p.nombre.toLowerCase()}">
              <div class="product-icon">${p.icon}</div>
              <div class="product-name">${p.nombre}</div>
              <div class="product-price">$${p.precio.toLocaleString('es-CO')}</div>
            </div>
          `).join('')}
        </div>
        <div class="tablet-order-panel">
          <div style="font-weight: 700; margin-bottom: 6px;">🧾 ${pedidoTarget ? pedidoTarget.nombre : '-'}</div>
          <div style="font-size: 0.82rem; color: var(--text-secondary);">Este pedido se refleja en Caja automáticamente.</div>
          ${crozzoCrmPosClientePanelHtml()}
          <div class="tablet-order-items" id="tabletOrderItems">
            ${cart.length ? cart.map(item => `
              <div class="cart-item">
                <div class="cart-item-info">
                  <div class="cart-item-name">${item.icon} ${item.nombreVenta || item.nombre}</div>
                  <div class="cart-item-price">$${item.precio.toLocaleString('es-CO')} x ${item.cantidad}</div>
                  ${item.detalleConfig ? `<div style="font-size:0.72rem; color:var(--text-muted);">${item.detalleConfig}</div>` : ''}
                </div>
                <div class="cart-item-qty">
                  ${tabCanEditQty ? `
                  <button type="button" class="qty-btn" onclick="tabletRemoveFromCart(${item.id}, '${item.configSig || ''}')">−</button>
                  <span>${item.cantidad}</span>
                  <button type="button" class="qty-btn" onclick="tabletAddToCart(${item.id}, '${item.configSig || ''}')">+</button>
                  ` : `<span class="qty-readonly" title="Sin permiso para editar cantidades">${item.cantidad} u.</span>`}
                </div>
              </div>
            `).join('') : `
              <div style="text-align:center; color: var(--text-muted); padding: 28px 8px;">Sin productos en este pedido</div>
            `}
          </div>
          <div class="cart-summary">
            <div class="cart-row"><span>${tabLabSub}</span><span>$${totals.subtotal.toLocaleString('es-CO')}</span></div>
            <div class="cart-row"><span>${tabLabIva}</span><span>$${totals.iva.toLocaleString('es-CO')}</span></div>
            <div class="cart-row cart-total"><span>Total</span><span>$${totals.total.toLocaleString('es-CO')}</span></div>
          </div>
          <button type="button" class="btn btn-outline" style="width: 100%;" onclick="tabletClearCart()" ${cart.length === 0 || !tabCanClearOrder ? 'disabled' : ''} title="${tabCanClearOrder ? 'Vaciar pedido actual' : 'Sin permiso para vaciar el pedido'}">Limpiar pedido</button>
          <button type="button" class="btn btn-primary" id="btnTabletConfirmComanda" style="width: 100%; margin-top: 8px;" onclick="showTabletConfirmComanda()" ${cart.length === 0 ? 'disabled' : ''}>✅ Confirmar y enviar a cocina</button>
          <div style="font-size: 0.75rem; color: var(--text-muted); margin-top: 8px;">
            ${tabCanEditQty ? 'Puedes ajustar cantidades.' : 'Solo lectura de cantidades: pide permiso «Editar orden».'}
            ${tabCanClearOrder ? '' : ' «Limpiar pedido» requiere permiso de eliminar ítems.'}
          </div>
        </div>
      </div>
    </div>
  `;
}
function crozzoRepEsc(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}
function crozzoRepFacturaTs(f) {
  const raw = f && (f.fecha || f.fechaEmision);
  return raw ? new Date(raw).getTime() : NaN;
}
function crozzoRepDayRange(d) {
  const x = d || new Date();
  const start = new Date(x.getFullYear(), x.getMonth(), x.getDate()).getTime();
  return { start, end: start + 86400000 };
}
function crozzoRepFilterFacturasToday() {
  const { start, end } = crozzoRepDayRange();
  return (typeof config !== 'undefined' && config.getFacturas ? config.getFacturas() : []).filter((f) => {
    const t = crozzoRepFacturaTs(f);
    return Number.isFinite(t) && t >= start && t < end;
  });
}
function crozzoRepDownloadCsv(filename, headers, rows) {
  const bom = '\uFEFF';
  const esc = (v) => '"' + String(v ?? '').replace(/"/g, '""') + '"';
  const lines = [headers.map(esc).join(',')];
  rows.forEach((r) => lines.push(r.map(esc).join(',')));
  const blob = new Blob([bom + lines.join('\n')], { type: 'text/csv;charset=utf-8;' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = filename;
  a.rel = 'noopener';
  a.click();
  URL.revokeObjectURL(a.href);
}
function crozzoRepExportVentasMes() {
  const now = new Date();
  const start = new Date(now.getFullYear(), now.getMonth(), 1).getTime();
  const end = new Date(now.getFullYear(), now.getMonth() + 1, 1).getTime();
  const invs = (config.getFacturas() || []).filter((f) => {
    const t = crozzoRepFacturaTs(f);
    return Number.isFinite(t) && t >= start && t < end;
  });
  const headers = ['Consecutivo', 'Fecha', 'Cliente', 'NIT', 'Subtotal', 'IVA', 'Total', 'MetodoPago', 'Estado', 'UUID'];
  const rows = invs.map((f) => [
    f.consecutivo || '',
    f.fecha || f.fechaEmision || '',
    f.compradorNombre || '',
    f.compradorNit || '',
    f.subtotal != null ? f.subtotal : '',
    f.iva != null ? f.iva : '',
    f.total != null ? f.total : '',
    f.metodoPago || '',
    f.estado || '',
    f.uuid || '',
  ]);
  crozzoRepDownloadCsv(`crozzo_ventas_mes_${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}.csv`, headers, rows);
  showToast('CSV generado (UTF-8 con BOM, compatible con Excel)', 'success');
}
function crozzoRepExportInventario() {
  const headers = ['id', 'sku', 'nombre', 'categoria', 'precio', 'stock', 'stockMin', 'fechaCaducidad', 'areaComanda'];
  const rows = (typeof products !== 'undefined' && Array.isArray(products) ? products : []).map((p) => [
    p.id,
    p.sku || '',
    p.nombre,
    p.categoria || '',
    p.precio,
    p.stock != null && !Number.isNaN(Number(p.stock)) ? Number(p.stock) : '',
    p.stockMin != null && !Number.isNaN(Number(p.stockMin)) ? Number(p.stockMin) : '',
    p.fechaCaducidad || '',
    p.areaComanda || '',
  ]);
  crozzoRepDownloadCsv(`crozzo_inventario_${new Date().toISOString().slice(0, 10)}.csv`, headers, rows);
  showToast('Inventario exportado', 'success');
}
function crozzoRepExportTurnos() {
  let h = [];
  try {
    h = JSON.parse(localStorage.getItem(CROZZO_SHIFT_TURN_HIST) || '[]');
  } catch (_) {
    h = [];
  }
  const headers = ['shiftId', 'openedAt', 'closedAt', 'ventasCount', 'totalVentas', 'ventasEfectivo', 'fondoCaja', 'efectivoEsperado', 'efectivoContado', 'diferencia', 'notas'];
  const rows = (Array.isArray(h) ? h : []).map((t) => [
    t.shiftId || '',
    t.openedAt || '',
    t.closedAt || '',
    t.salesCount ?? '',
    t.totalSales ?? '',
    t.cashSales ?? '',
    t.fondo ?? '',
    t.expected ?? '',
    t.actual ?? '',
    t.diff ?? '',
    String(t.notes || '').replace(/\r?\n/g, ' '),
  ]);
  crozzoRepDownloadCsv(`crozzo_cierres_turno_${new Date().toISOString().slice(0, 10)}.csv`, headers, rows);
  showToast('Cierres de turno exportados', 'success');
}
function crozzoRepRefreshVentas() {
  const list = crozzoRepFilterFacturasToday();
  let total = 0;
  let iva = 0;
  const topMap = {};
  list.forEach((f) => {
    total += Number(f.total) || 0;
    iva += Number(f.iva) || 0;
    (f.items || []).forEach((it) => {
      const name = it.nombreVenta || it.nombre || 'Ítem';
      const q = Number(it.cantidad) || 0;
      const rev = (Number(it.precio) || 0) * q;
      if (!topMap[name]) topMap[name] = { qty: 0, rev: 0 };
      topMap[name].qty += q;
      topMap[name].rev += rev;
    });
  });
  const count = list.length;
  const avg = count ? Math.round(total / count) : 0;
  const set = (id, v) => {
    const n = document.getElementById(id);
    if (n) n.textContent = v;
  };
  set('crozzo-rep-kpi-today', '$' + Math.round(total).toLocaleString('es-CO'));
  set('crozzo-rep-kpi-count', String(count));
  set('crozzo-rep-kpi-avg', '$' + avg.toLocaleString('es-CO'));
  set('crozzo-rep-kpi-iva', '$' + Math.round(iva).toLocaleString('es-CO'));
  const top = Object.entries(topMap).sort((a, b) => b[1].qty - a[1].qty).slice(0, 10);
  const tb = document.querySelector('#crozzo-rep-top-products tbody');
  if (tb) {
    tb.innerHTML = top.length
      ? top
          .map(
            ([n, d]) =>
              `<tr><td>${crozzoRepEsc(n)}</td><td>${d.qty}</td><td>$${Math.round(d.rev).toLocaleString('es-CO')}</td></tr>`
          )
          .join('')
      : '<tr><td colspan="3" style="text-align:center;color:var(--text-muted);">Sin ventas hoy (fecha local del equipo)</td></tr>';
  }
}
function crozzoRepInvPatch(id, field, raw) {
  const idx = products.findIndex((p) => String(p.id) === String(id));
  if (idx < 0) return;
  const p = { ...products[idx] };
  if (field === 'sku') {
    p.sku = String(raw || '').trim();
  } else if (field === 'caduca') {
    const s = String(raw || '').trim();
    if (s) p.fechaCaducidad = s;
    else delete p.fechaCaducidad;
  } else {
    if (field === 'stock' && (raw === '' || raw == null)) {
      delete p.stock;
    } else if (field === 'stockMin' && (raw === '' || raw == null)) {
      delete p.stockMin;
    } else {
      const n = Math.max(0, parseFloat(String(raw).replace(',', '.')) || 0);
      if (field === 'stock') p.stock = n;
      if (field === 'stockMin') p.stockMin = n;
    }
  }
  products[idx] = p;
  persistCatalogProductosLocal();
  try {
    persistCatalogProductos(id);
  } catch (_) {}
  showToast('Catálogo actualizado', 'success');
}
function crozzoRepRefreshInventarioTab() {
  const tb = document.querySelector('#crozzo-rep-inv-table tbody');
  if (!tb) return;
  if (typeof products === 'undefined' || !products.length) {
    tb.innerHTML = '<tr><td colspan="6" style="text-align:center;color:var(--text-muted);">Sin productos en catálogo</td></tr>';
    return;
  }
  tb.innerHTML = products
    .map((p) => {
      const tracked = p.stock != null && !Number.isNaN(Number(p.stock));
      const st = tracked
        ? Number(p.stock) <= crozzoStockThresholdForProduct(p)
          ? '<span style="color:var(--danger);font-weight:700;">Bajo</span>'
          : '<span style="color:var(--success);">OK</span>'
        : '<span style="color:var(--text-muted);">Sin control</span>';
      const sku = p.sku || `P-${p.id}`;
      return `<tr>
        <td><input class="form-input" style="min-width:72px;padding:4px 6px;font-size:0.78rem;" value="${crozzoRepEsc(sku)}" onchange="crozzoRepInvPatch(${p.id},'sku',this.value)"></td>
        <td>${crozzoRepEsc(p.nombre)}</td>
        <td><input type="number" min="0" step="1" class="form-input" style="max-width:88px;padding:4px 6px;" value="${tracked ? Number(p.stock) : ''}" placeholder="—" onchange="crozzoRepInvPatch(${p.id},'stock',this.value)"></td>
        <td><input type="number" min="0" step="1" class="form-input" style="max-width:72px;padding:4px 6px;" value="${p.stockMin != null ? Number(p.stockMin) : ''}" placeholder="${CROZZO_STOCK_ALERT_DEFAULT}" onchange="crozzoRepInvPatch(${p.id},'stockMin',this.value)"></td>
        <td><input type="date" class="form-input" style="max-width:132px;padding:4px 6px;font-size:0.75rem;" value="${p.fechaCaducidad ? String(p.fechaCaducidad).slice(0, 10) : ''}" onchange="crozzoRepInvPatch(${p.id},'caduca',this.value)"></td>
        <td>${st}</td>
      </tr>`;
    })
    .join('');
}
function crozzoRepRefreshPredictions() {
  const el = document.getElementById('crozzo-rep-predict-list');
  if (!el) return;
  const alerts = [];
  const low = typeof crozzoShiftLowStockProducts === 'function' ? crozzoShiftLowStockProducts() : [];
  low.forEach((p) => {
    alerts.push({
      cls: 'warn',
      html: `<strong>${crozzoRepEsc(p.nombre)}</strong>: stock ${Number(p.stock)} (umbral ${crozzoStockThresholdForProduct(p)}).`,
    });
  });
  const now = new Date();
  const dow = now.getDay();
  const h = now.getHours();
  if (dow === 6 && h >= 17 && h <= 22) {
    alerts.push({ cls: '', html: '📈 Sábado noche: revisa stock de bebidas y caja.' });
  } else if ((dow === 5 || dow === 6) && h >= 19 && h <= 21) {
    alerts.push({ cls: '', html: '📈 Horario de cena: anticipa cocina y bar.' });
  }
  const msDay = 86400000;
  (typeof products !== 'undefined' && Array.isArray(products) ? products : []).forEach((p) => {
    const fc = p.fechaCaducidad || p.caduca;
    if (!fc) return;
    const t = new Date(fc).getTime();
    if (!Number.isFinite(t)) return;
    const days = Math.ceil((t - now.getTime()) / msDay);
    if (days >= 0 && days <= 3) {
      alerts.push({
        cls: days === 0 ? 'crit' : 'warn',
        html: `⏰ <strong>${crozzoRepEsc(p.nombre)}</strong>: caduca ${days === 0 ? 'hoy' : 'en ' + days + ' día(s)'} (${String(fc).slice(0, 10)}).`,
      });
    }
  });
  el.innerHTML = alerts.length
    ? alerts.map((a) => `<div class="crozzo-rep-pred ${a.cls}">${a.html}</div>`).join('')
    : '<p style="color:var(--text-muted);">Sin alertas activas.</p>';
}
function crozzoRepOpenReceiveModal() {
  if (typeof products === 'undefined' || !products.length) {
    showToast('No hay productos en catálogo', 'warning');
    return;
  }
  const opts = products.map((p) => `<option value="${p.id}">${crozzoRepEsc(p.nombre)}</option>`).join('');
  showModal('Recibir mercancía', `
    <div class="fade-in">
      <p class="form-hint" style="margin-bottom:10px;">Suma unidades al <strong>stock</strong> del producto (persiste en catálogo local / nube).</p>
      <div class="form-group">
        <label class="form-label">Producto</label>
        <select class="form-select" id="crozzoRepRecvPid">${opts}</select>
      </div>
      <div class="form-group">
        <label class="form-label">Cantidad a ingresar</label>
        <input type="number" min="1" step="1" class="form-input" id="crozzoRepRecvQty" value="1">
      </div>
      <div class="btn-group" style="justify-content:flex-end;">
        <button type="button" class="btn btn-outline" onclick="closeModal()">Cancelar</button>
        <button type="button" class="btn btn-primary" onclick="crozzoRepConfirmReceive()">Agregar stock</button>
      </div>
    </div>
  `);
}
function crozzoRepConfirmReceive() {
  const pid = document.getElementById('crozzoRepRecvPid')?.value;
  const qty = Number(document.getElementById('crozzoRepRecvQty')?.value || 0);
  if (!pid || qty <= 0) {
    showToast('Indica cantidad válida', 'warning');
    return;
  }
  const idx = products.findIndex((p) => String(p.id) === String(pid));
  if (idx < 0) return;
  const p = products[idx];
  const base = p.stock != null && !Number.isNaN(Number(p.stock)) ? Number(p.stock) : 0;
  products[idx] = { ...p, stock: base + qty };
  persistCatalogProductosLocal();
  try {
    persistCatalogProductos(p.id);
  } catch (_) {}
  closeModal();
  crozzoRepRefreshInventarioTab();
  crozzoRepRefreshPredictions();
  showToast('Recepción aplicada', 'success');
}
function initInventariosReportes() {
  const root = document.getElementById('crozzo-rep-root');
  if (!root) return;
  if (!root.__crozzoRepBound) {
    root.__crozzoRepBound = true;
    root.addEventListener('click', (e) => {
      const tab = e.target.closest('.crozzo-rep-tab');
      if (!tab || !root.contains(tab)) return;
      const name = tab.getAttribute('data-rep-tab');
      root.querySelectorAll('.crozzo-rep-tab').forEach((t) => t.classList.toggle('active', t === tab));
      root.querySelectorAll('.crozzo-rep-panel').forEach((panel) => {
        panel.style.display = panel.getAttribute('data-rep-panel') === name ? '' : 'none';
      });
      if (name === 'ventas') crozzoRepRefreshVentas();
      if (name === 'inv') crozzoRepRefreshInventarioTab();
      if (name === 'compras') crozzoRepRefreshComprasTab();
      if (name === 'pred') crozzoRepRefreshPredictions();
    });
  }
  crozzoRepRefreshVentas();
  crozzoRepRefreshInventarioTab();
  crozzoRepRefreshPredictions();
  if (window.__crozzoInventariosTab) {
    var want = window.__crozzoInventariosTab;
    window.__crozzoInventariosTab = null;
    var tabBtn = root.querySelector('.crozzo-rep-tab[data-rep-tab="' + want + '"]');
    if (tabBtn) tabBtn.click();
  }
}
function crozzoRepRefreshComprasTab() {
  var host = document.getElementById('crozzo-rep-compras-host');
  if (!host) return;
  if (typeof CrozzoComprasLocal !== 'undefined' && CrozzoComprasLocal.render) {
    host.innerHTML = CrozzoComprasLocal.render('dashboard');
    if (CrozzoComprasLocal.init) CrozzoComprasLocal.init(host, 'dashboard');
    return;
  }
  host.innerHTML = '<div class="card"><p class="page-subtitle">No se pudo cargar el resumen local de compras.</p></div>';
}
function crozzoInvDeductFromFactura(factura) {
  if (typeof products === 'undefined' || !Array.isArray(factura.items)) return;
  let changed = false;
  const touched = new Set();
  factura.items.forEach((line) => {
    const pid = line.id;
    if (pid == null) return;
    const idx = products.findIndex((p) => String(p.id) === String(pid));
    if (idx < 0) return;
    const p = products[idx];
    if (p.stock == null || Number.isNaN(Number(p.stock))) return;
    const qty = Number(line.cantidad) || 0;
    if (qty <= 0) return;
    const cur = Number(p.stock);
    products[idx] = { ...p, stock: Math.max(0, cur - qty) };
    changed = true;
    touched.add(pid);
  });
  if (changed) {
    persistCatalogProductosLocal();
    touched.forEach((id) => {
      try {
        persistCatalogProductos(id);
      } catch (_) {}
    });
  }
}
function renderInventarios() {
  return `
    <div class="card crozzo-rep-root" id="crozzo-rep-root">
      <div class="card-header">
        <div>
          <h2 class="card-title">Reportes e inventario</h2>
          <p class="page-subtitle" style="margin-top:4px;">KPIs del día, stock del catálogo, exportación contable CSV y alertas</p>
        </div>
      </div>
      <div class="alert alert-info" style="margin-bottom:14px;">
        <span>ℹ️</span>
        <div style="font-size:0.85rem;">
          El <strong>descuento de stock</strong> se aplica al cobrar solo si el producto tiene <code>stock</code> numérico en catálogo.
          Los CSV usan <strong>UTF-8 con BOM</strong> para abrir bien en Excel / Siigo (importar como delimitado por comas).
          Un analizador externo tipo “Scenario” con Chart.js/Tailwind es pesado para este archivo; exporta ventas y trabaja el escenario en hoja de cálculo o en una app aparte si la necesitas embebida.
        </div>
      </div>
      <div class="crozzo-rep-tabs">
        <button type="button" class="crozzo-rep-tab active" data-rep-tab="ventas">📈 Ventas hoy</button>
        <button type="button" class="crozzo-rep-tab" data-rep-tab="inv">📦 Inventario</button>
        <button type="button" class="crozzo-rep-tab" data-rep-tab="compras">🏭 Resumen compras</button>
        <button type="button" class="crozzo-rep-tab" data-rep-tab="export">📥 Exportar CSV</button>
        <button type="button" class="crozzo-rep-tab" data-rep-tab="pred">🔮 Alertas</button>
      </div>
      <div class="crozzo-rep-panel" data-rep-panel="ventas">
        <div class="crozzo-rep-kpi-grid">
          <div class="crozzo-rep-kpi"><div class="val" id="crozzo-rep-kpi-today">$0</div><div class="lbl">Ventas hoy</div></div>
          <div class="crozzo-rep-kpi"><div class="val" id="crozzo-rep-kpi-count">0</div><div class="lbl">Transacciones</div></div>
          <div class="crozzo-rep-kpi"><div class="val" id="crozzo-rep-kpi-avg">$0</div><div class="lbl">Ticket medio</div></div>
          <div class="crozzo-rep-kpi"><div class="val" id="crozzo-rep-kpi-iva">$0</div><div class="lbl">IVA (líneas)</div></div>
        </div>
        <h3 style="font-size:0.95rem;margin-bottom:8px;">Top productos (hoy)</h3>
        <div class="crozzo-rep-table-wrap">
          <table id="crozzo-rep-top-products">
            <thead><tr><th>Producto</th><th>Cant.</th><th>Ingresos</th></tr></thead>
            <tbody></tbody>
          </table>
        </div>
      </div>
      <div class="crozzo-rep-panel" data-rep-panel="inv" style="display:none;">
        <div class="crozzo-rep-actions">
          <button type="button" class="btn btn-primary" onclick="crozzoRepOpenReceiveModal()">📥 Recibir mercancía</button>
          <button type="button" class="btn btn-outline" onclick="crozzoRepRefreshInventarioTab(); showToast('Tabla actualizada', 'info');">🔄 Refrescar</button>
        </div>
        <div class="crozzo-rep-table-wrap">
          <table id="crozzo-rep-inv-table">
            <thead><tr><th>SKU editable</th><th>Producto</th><th>Stock</th><th>Mín.</th><th>Caduca</th><th>Estado</th></tr></thead>
            <tbody></tbody>
          </table>
        </div>
      </div>
      <div class="crozzo-rep-panel" data-rep-panel="compras" style="display:none;">
        <p class="page-subtitle" style="margin:0 0 12px">Indicadores del flujo de compras (recepción, cortes, oficina). Con nube activa el detalle completo está en cada módulo del menú lateral.</p>
        <div id="crozzo-rep-compras-host"></div>
      </div>
      <div class="crozzo-rep-panel" data-rep-panel="export" style="display:none;">
        <p style="color:var(--text-secondary);font-size:0.88rem;margin-bottom:12px;">Descarga datos reales del POS (facturas en <code>pos_dian_config</code>, catálogo e historial de cierres de turno).</p>
        <div class="crozzo-rep-actions">
          <button type="button" class="btn btn-outline" onclick="crozzoRepExportVentasMes()">📄 Ventas del mes</button>
          <button type="button" class="btn btn-outline" onclick="crozzoRepExportInventario()">📦 Inventario actual</button>
          <button type="button" class="btn btn-outline" onclick="crozzoRepExportTurnos()">🔒 Cierres de turno</button>
        </div>
      </div>
      <div class="crozzo-rep-panel" data-rep-panel="pred" style="display:none;">
        <h3 style="font-size:0.95rem;margin-bottom:10px;">Alertas predictivas (reglas simples)</h3>
        <div id="crozzo-rep-predict-list"></div>
      </div>
    </div>
  `;
}
function crozzoEnsureProveedoresExtensions() {
  if (typeof config === 'undefined' || !config.get || !config.set) return;
  const modes = ['online', 'hybrid', 'offline'];
  if (!modes.includes(config.get('runtimeSyncModo'))) config.set('runtimeSyncModo', 'hybrid');
  if (!Array.isArray(config.get('proveedoresOC'))) config.set('proveedoresOC', []);
  if (!Array.isArray(config.get('ordenesCompra'))) config.set('ordenesCompra', []);
}
function crozzoGetProveedoresUnificados() {
  crozzoEnsureProveedoresExtensions();
  if (typeof CrozzoReservorio !== 'undefined' && CrozzoReservorio.listProveedoresOcFormat) {
    return CrozzoReservorio.listProveedoresOcFormat();
  }
  return config.get('proveedoresOC') || [];
}
function renderComprasProveedores(opts) {
  opts = opts || {};
  const view = opts.view || 'full';
  const initialTab = opts.initialTab || window.__crozzoProvOpenTab || 'prov';
  crozzoEnsureProveedoresExtensions();
  const provs = crozzoGetProveedoresUnificados();
  const orders = [...(config.get('ordenesCompra') || [])].sort((a, b) =>
    String(b.date || '').localeCompare(String(a.date || ''))
  );
  const mode = config.get('runtimeSyncModo') || 'hybrid';
  const low = typeof crozzoShiftLowStockProducts === 'function' ? crozzoShiftLowStockProducts() : [];
  const prodOpts =
    typeof products !== 'undefined' && Array.isArray(products)
      ? products
          .map(
            (p) =>
              `<option value="${String(p.id).replace(/"/g, '&quot;')}">${escUserAttr(String(p.nombre || ''))}</option>`
          )
          .join('')
      : '';
  const provCards = provs
    .map((s) => {
      const sid = String(s.id || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
      const nombre = String(s.name || s.nombre || '');
      const nit = String(s.nit || '—');
      const tel = String(s.phone || s.telefono || '—');
      const rubro = String(s.tipoRubro || s.categoria || '—');
      const searchBlob = [nombre, nit, tel, rubro, s.id].join(' ').toLowerCase();
      const ini = nombre
        .trim()
        .split(/\s+/)
        .slice(0, 2)
        .map((w) => w.charAt(0))
        .join('')
        .toUpperCase() || '?';
      let badges = '';
      let bancoHint = '';
      let rutHint = '';
      try {
        if (typeof CrozzoReservorio !== 'undefined' && CrozzoReservorio.getProveedor) {
          const full = CrozzoReservorio.getProveedor(s.id);
          const leg = full && full.legal;
          const doc = leg && leg.document;
          const est = leg && leg.vigencia && leg.vigencia.estado;
          if (doc && doc.blobId) {
            badges += ' <span class="badge badge-info" title="Certificado RUT archivado">RUT</span>';
            if (est && typeof CrozzoProveedorDocumentos !== 'undefined' && CrozzoProveedorDocumentos.vigenciaBadge) {
              badges += CrozzoProveedorDocumentos.vigenciaBadge(est);
            }
            const rutNombre = String(doc.nombre || 'Certificado.pdf');
            const vigLabel =
              est === 'vigente'
                ? 'Vigente'
                : est === 'por_vencer'
                  ? 'Por revisar'
                  : est === 'desactualizado'
                    ? 'Desactualizado'
                    : 'Sin fecha clara';
            rutHint =
              '<p class="crozzo-prov-dir__rut form-hint" title="Certificado tributario">📄 ' +
              escUserAttr(rutNombre) +
              ' · ' +
              escUserAttr(vigLabel) +
              '</p>';
          } else {
            badges += ' <span class="badge" style="opacity:0.75">Sin RUT</span>';
          }
          if (leg && leg.retenciones) {
            if (leg.retenciones.exento) {
              badges += ' <span class="badge badge-success">Sin ret.</span>';
            } else if (leg.retenciones.aplicaRetencion) {
              badges += ' <span class="badge badge-warning">Retención</span>';
            }
            if (leg.retenciones.retencionICA && leg.retenciones.retencionICA.aplica) {
              badges += ' <span class="badge badge-warning">RETE ICA</span>';
            }
          }
          if (leg && leg.tipoPersona && leg.tipoPersona.tipo && leg.tipoPersona.tipo !== 'desconocido') {
            badges +=
              ' <span class="badge badge-info">' +
              escUserAttr(leg.tipoPersona.tipo === 'juridica' ? 'Jurídica' : 'Natural') +
              '</span>';
          }
          if (leg && leg.nombreParaTransferencias) {
            bancoHint =
              '<p class="crozzo-prov-dir__bank form-hint" title="Nombre para transferencias">🏦 ' +
              escUserAttr(String(leg.nombreParaTransferencias)) +
              '</p>';
          }
        }
      } catch (_) {}
      return `
      <article class="crozzo-prov-dir__card" data-prov-card data-prov-search="${escUserAttr(searchBlob)}" data-prov-id="${escUserAttr(String(s.id || ''))}">
        <div class="crozzo-prov-dir__card-top">
          <div class="crozzo-prov-dir__avatar" aria-hidden="true">${escUserAttr(ini)}</div>
          <div class="crozzo-prov-dir__card-main">
            <h4 class="crozzo-prov-dir__name">${escUserAttr(nombre)}</h4>
            <p class="crozzo-prov-dir__meta">${escUserAttr(nit)} · ${escUserAttr(rubro)}</p>
            ${rutHint}
            ${bancoHint}
            <p class="crozzo-prov-dir__tel form-hint">📞 ${escUserAttr(tel)}</p>
            <div class="crozzo-prov-dir__badges">${badges || '<span class="form-hint">Sin certificado RUT</span>'}</div>
          </div>
        </div>
        <div class="crozzo-prov-dir__actions">
          <button type="button" class="btn btn-outline btn-sm" onclick="crozzoProvView('${sid}')" title="Ver ficha completa">Ver</button>
          <button type="button" class="btn btn-primary btn-sm" onclick="crozzoProvEdit('${sid}')" title="Editar datos">Editar</button>
          <button type="button" class="btn btn-outline btn-sm crozzo-prov-dir__btn-danger" onclick="crozzoProvDelete('${sid}')" title="Quitar del directorio">Eliminar</button>
        </div>
      </article>`;
    })
    .join('');
  const orderRows = orders
    .map((po) => {
      const st = String(po.status || 'pendiente');
      const badge =
        st === 'recibido' ? 'badge-success' : st === 'transito' ? 'badge-info' : 'badge-warning';
      const safeId = String(po.id || '').replace(/'/g, "\\'");
      return `
      <tr>
        <td><strong>${escUserAttr(String(po.id || ''))}</strong></td>
        <td>${escUserAttr(String(po.supplierName || ''))}</td>
        <td><span class="badge ${badge}">${escUserAttr(st)}</span></td>
        <td style="white-space:nowrap;">${po.date ? new Date(po.date).toLocaleString('es-CO') : '—'}</td>
        <td>
          ${
            st === 'pendiente'
              ? `<button type="button" class="btn btn-outline" style="padding:4px 8px;font-size:0.78rem;" onclick="crozzoOpPOTransit('${safeId}')">En tránsito</button>`
              : ''
          }
          ${
            st === 'transito'
              ? `<button type="button" class="btn btn-primary" style="padding:4px 8px;font-size:0.78rem;" onclick="crozzoOpPOReceive('${safeId}')">Recibir</button>`
              : ''
          }
          ${st === 'recibido' ? '<span class="form-hint">Stock OK</span>' : ''}
        </td>
      </tr>`;
    })
    .join('');
  const lowChips = low
    .slice(0, 14)
    .map(
      (p) =>
        `<button type="button" class="btn btn-outline" style="margin:3px;font-size:0.78rem;" onclick="crozzoOpAddPoLineFromProduct(${Number(
          p.id
        )})">${escUserAttr(String(p.nombre || ''))} <span class="form-hint">(${p.stock})</span></button>`
    )
    .join('');
  const supOpts =
    provs
      .map(
        (s) =>
          `<option value="${String(s.id).replace(/"/g, '&quot;')}">${escUserAttr(String(s.name || ''))}</option>`
      )
      .join('') || '<option value="">— Sin proveedores —</option>';

  const poPanelInner = `
        <p class="form-hint">Sugerencias de stock bajo:</p>
        <div style="margin-bottom:10px;">${
          low.length ? lowChips : '<span class="form-hint">Inventario por encima de umbrales</span>'
        }</div>
        <div class="form-grid" style="margin-bottom:10px;">
          <div class="form-group">
            <label class="form-label">Proveedor</label>
            <select class="form-select" id="crozzo-op-po-supplier">${supOpts}</select>
          </div>
          <div class="form-group">
            <label class="form-label">Producto</label>
            <select class="form-select" id="crozzo-op-po-product">${prodOpts || '<option value="">Sin catálogo</option>'}</select>
          </div>
          <div class="form-group">
            <label class="form-label">Cantidad</label>
            <input type="number" min="1" class="form-input" id="crozzo-op-po-qty" value="10">
          </div>
        </div>
        <button type="button" class="btn btn-outline" onclick="crozzoOpPoAddLine()">Añadir línea al borrador</button>
        <button type="button" class="btn btn-primary" onclick="crozzoOpPoCreate()" style="margin-left:8px;">Crear orden</button>
        <p class="form-hint" style="margin:8px 0 0">¿Falta un proveedor? <button type="button" class="btn btn-link btn-sm" onclick="crozzoNavProveedores('prov')">Abrir directorio</button></p>
        <div id="crozzo-op-po-draft" style="margin:12px 0;padding:10px;border:1px dashed var(--border);border-radius:var(--radius);min-height:40px;font-size:0.85rem;">Borrador vacío — agrega líneas.</div>
        <div class="table-container" style="margin-top:10px;">
          <table>
            <thead><tr><th>OC</th><th>Proveedor</th><th>Estado</th><th>Fecha</th><th>Acción</th></tr></thead>
            <tbody>${
              orderRows ||
              '<tr><td colspan="5" style="text-align:center;color:var(--text-muted);">Sin órdenes</td></tr>'
            }</tbody>
          </table>
        </div>`;
  const poPanelHtml = `<div class="crozzo-rep-panel" data-op-panel="po" style="display:none;">${poPanelInner}</div>`;

  if (view === 'ordenes') {
    return `
    <div class="card crozzo-rep-root" id="crozzo-op-root" data-prov-view="ordenes">
      <div class="card-header" style="display:flex;flex-wrap:wrap;gap:8px;align-items:center;justify-content:space-between">
        <div>
          <h2 class="card-title">Órdenes de compra</h2>
          <p class="page-subtitle" style="margin-top:4px;">Stock del catálogo POS</p>
        </div>
        <button type="button" class="btn btn-outline btn-sm" onclick="navigateTo('compras-proveedores')">Directorio proveedores</button>
      </div>
      <div class="crozzo-rep-panel" data-op-panel="po">${poPanelInner}</div>
    </div>`;
  }

  const tabActive = (t) => (t === initialTab ? ' active' : '');
  const panelDisplay = (t) => (t === initialTab ? '' : ' style="display:none;"');
  return `
    <div class="card crozzo-rep-root" id="crozzo-op-root" data-prov-view="full">
      <div class="card-header" style="display:flex;flex-wrap:wrap;gap:8px;align-items:flex-start;justify-content:space-between">
        <div>
          <h2 class="card-title">Directorio de proveedores</h2>
          <p class="page-subtitle" style="margin-top:4px;">Un solo listado para compras, costos y entrada de factura (reservorio unificado)</p>
        </div>
        <button type="button" class="btn btn-outline btn-sm" onclick="navigateTo('compras-recepcion')">Entrada de factura →</button>
      </div>
      <div class="crozzo-rep-tabs" id="crozzo-op-tabs">
        <button type="button" class="crozzo-rep-tab${tabActive('prov')}" data-op-tab="prov">Listado</button>
        <button type="button" class="crozzo-rep-tab${tabActive('import')}" data-op-tab="import">Importar certificado</button>
        <button type="button" class="crozzo-rep-tab${tabActive('po')}" data-op-tab="po">Órdenes de stock</button>
      </div>
      <div class="crozzo-rep-panel crozzo-prov-dir" data-op-panel="prov"${panelDisplay('prov')}>
        <div class="crozzo-prov-dir__toolbar">
          <div class="crozzo-prov-dir__search-wrap">
            <span class="crozzo-prov-dir__search-icon" aria-hidden="true">🔎</span>
            <input type="search" class="form-input crozzo-prov-dir__search" id="crozzo-prov-search" placeholder="Buscar por nombre, NIT, teléfono, rubro…" oninput="crozzoProvFilterList()">
          </div>
          <div class="crozzo-prov-dir__toolbar-actions">
            <button type="button" class="btn btn-outline btn-sm" onclick="crozzoOpSwitchProvTab('import')">📄 Importar RUT</button>
          </div>
        </div>
        <details class="crozzo-prov-dir__quick-add">
          <summary class="crozzo-prov-dir__quick-add-title">＋ Alta rápida manual</summary>
          <div class="crozzo-prov-dir__quick-add-body">
            <div class="form-grid">
              <div class="form-group">
                <label class="form-label">Nombre en directorio</label>
                <input class="form-input" id="crozzo-op-prov-name" placeholder="Ej: Distribuidora ABC">
              </div>
              <div class="form-group">
                <label class="form-label" id="crozzo-op-prov-nit-label">NIT / RUT</label>
                <input class="form-input" id="crozzo-op-prov-nit" placeholder="900.123.456-7">
              </div>
              <div class="form-group">
                <label class="form-label">Rubro</label>
                <select class="form-input" id="crozzo-op-prov-rubro">
                  <option value="Carnicería">Carnicería</option>
                  <option value="Quesería">Quesería</option>
                  <option value="Verduras y frutas">Verduras y frutas</option>
                  <option value="Abarrotes">Abarrotes</option>
                  <option value="Bebidas">Bebidas</option>
                  <option value="Panadería">Panadería</option>
                  <option value="Lácteos">Lácteos</option>
                  <option value="Pescadería">Pescadería</option>
                  <option value="Empaques">Empaques</option>
                  <option value="Otro">Otro</option>
                </select>
              </div>
              <div class="form-group">
                <label class="form-label">Teléfono</label>
                <input class="form-input" id="crozzo-op-prov-tel" placeholder="300…">
              </div>
            </div>
            <button type="button" class="btn btn-primary btn-sm" onclick="crozzoOpAddSupplier()">Guardar proveedor</button>
          </div>
        </details>
        <div class="crozzo-prov-dir__grid" id="crozzo-prov-grid">${
          provCards ||
          '<p class="crozzo-prov-dir__empty">Sin proveedores. Importe un certificado RUT o use alta rápida.</p>'
        }</div>
        <p class="form-hint crozzo-prov-dir__footer-hint">${provs.length} proveedor${provs.length === 1 ? '' : 'es'} en el directorio unificado (compras y facturación).</p>
      </div>
      <div class="crozzo-rep-panel" data-op-panel="import"${panelDisplay('import')}>
        ${
          typeof CrozzoProveedorDocumentos !== 'undefined' && CrozzoProveedorDocumentos.renderImportBlock
            ? CrozzoProveedorDocumentos.renderImportBlock('crozzo-op')
            : '<p class="form-hint">Cargue el módulo de reservorio (recargue la página).</p>'
        }
      </div>
      ${poPanelHtml}
      <details class="crozzo-prov-advanced" style="margin-top:16px">
        <summary class="form-hint" style="cursor:pointer">Opciones técnicas (sync y diagnóstico local)</summary>
        <div style="padding:12px 0">
          <p class="form-hint" style="margin-bottom:8px">Modo de trabajo con red en este equipo. Actual: <strong>${escUserAttr(String(mode))}</strong></p>
          <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px">
            <button type="button" class="btn ${mode === 'online' ? 'btn-primary' : 'btn-outline'}" onclick="crozzoOpSetRuntimeMode('online')">Online</button>
            <button type="button" class="btn ${mode === 'hybrid' ? 'btn-primary' : 'btn-outline'}" onclick="crozzoOpSetRuntimeMode('hybrid')">Híbrido</button>
            <button type="button" class="btn ${mode === 'offline' ? 'btn-primary' : 'btn-outline'}" onclick="crozzoOpSetRuntimeMode('offline')">Offline</button>
          </div>
          <button type="button" class="btn btn-outline btn-sm" onclick="crozzoOpRunDiagnostics()">Diagnóstico rápido</button>
          <div id="crozzo-op-diag-out" style="margin-top:10px;display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px;"></div>
        </div>
      </details>
    </div>
  `;
}
function crozzoProvGetFull(id) {
  if (typeof CrozzoReservorio !== 'undefined' && CrozzoReservorio.getProveedor) {
    return CrozzoReservorio.getProveedor(id);
  }
  return (crozzoGetProveedoresUnificados() || []).find((p) => String(p.id) === String(id));
}
function crozzoProvFilterList() {
  const q = String(document.getElementById('crozzo-prov-search')?.value || '')
    .trim()
    .toLowerCase();
  document.querySelectorAll('[data-prov-card]').forEach((card) => {
    const blob = (card.getAttribute('data-prov-search') || '').toLowerCase();
    card.style.display = !q || blob.indexOf(q) >= 0 ? '' : 'none';
  });
}
function crozzoProvView(id) {
  const p = crozzoProvGetFull(id);
  if (!p) return showToast('Proveedor no encontrado', 'error');
  const body =
    typeof CrozzoProveedorDocumentos !== 'undefined' && CrozzoProveedorDocumentos.renderProveedorFicha
      ? CrozzoProveedorDocumentos.renderProveedorFicha(p)
      : '<p class="form-hint">Sin módulo de ficha.</p>';
  const leg = p.legal && typeof p.legal === 'object' ? p.legal : {};
  const tieneRut = !!(leg.document && leg.document.blobId);
  const sid = String(id).replace(/'/g, "\\'");
  const footer =
    '<div style="margin-top:14px;display:flex;gap:8px;flex-wrap:wrap">' +
    (tieneRut
      ? '<button type="button" class="btn btn-outline btn-sm" onclick="crozzoProvViewRut(\'' +
        sid +
        '\')">Ver RUT</button>'
      : '') +
    '<button type="button" class="btn btn-primary btn-sm" onclick="closeModal();crozzoProvEdit(\'' +
    sid +
    '\')">Editar</button>' +
    '<button type="button" class="btn btn-outline btn-sm" onclick="closeModal()">Cerrar</button></div>';
  showModal('Proveedor · ' + (p.nombre || ''), body + footer, { wide: true, modalClass: 'modal--prov-ficha' });
}
function crozzoProvViewRut(id) {
  if (typeof CrozzoProveedorDocumentos !== 'undefined' && CrozzoProveedorDocumentos.openProveedorRut) {
    CrozzoProveedorDocumentos.openProveedorRut(id);
    return;
  }
  showToast('No se puede abrir el certificado', 'error');
}
function crozzoProvEdit(id) {
  const p = crozzoProvGetFull(id);
  if (!p) return showToast('Proveedor no encontrado', 'error');
  const body =
    typeof CrozzoProveedorDocumentos !== 'undefined' && CrozzoProveedorDocumentos.renderProveedorEditForm
      ? CrozzoProveedorDocumentos.renderProveedorEditForm(p)
      : '<p class="form-hint">Sin formulario de edición.</p>';
  showModal('Editar · ' + (p.nombre || ''), body, { wide: true, modalClass: 'modal--prov-edit' });
}
function crozzoProvSaveEdit() {
  const id = document.getElementById('crozzo-prov-edit-id')?.value;
  const nombre = (document.getElementById('crozzo-prov-edit-nombre')?.value || '').trim();
  if (!id || !nombre) return showToast('Nombre requerido', 'warning');
  const prev = crozzoProvGetFull(id) || {};
  const legPrev = prev.legal && typeof prev.legal === 'object' ? prev.legal : {};
  const ciudadEdit = (document.getElementById('crozzo-prov-edit-ciudad')?.value || '').trim();
  let retenciones = legPrev.retenciones || null;
  if (
    typeof CrozzoProveedorDocumentos !== 'undefined' &&
    CrozzoProveedorDocumentos.computeRetencionesProveedor
  ) {
    retenciones = CrozzoProveedorDocumentos.computeRetencionesProveedor(
      legPrev.regimenTributario || {},
      legPrev.obligaciones || [],
      legPrev.tipoPersona,
      { ciudadProveedor: ciudadEdit }
    );
  }
  const payload = {
    id: id,
    nombre: nombre,
    nit: (document.getElementById('crozzo-prov-edit-nit')?.value || '').trim(),
    telefono: (document.getElementById('crozzo-prov-edit-tel')?.value || '').trim(),
    email: (document.getElementById('crozzo-prov-edit-email')?.value || '').trim(),
    tipoRubro: document.getElementById('crozzo-prov-edit-rubro')?.value || 'Otro',
    representante: (document.getElementById('crozzo-prov-edit-rep')?.value || '').trim(),
    legal: Object.assign({}, legPrev, {
      razonSocial: (document.getElementById('crozzo-prov-edit-razon')?.value || '').trim(),
      nombreComercial: (document.getElementById('crozzo-prov-edit-comercial')?.value || '').trim(),
      nombreParaTransferencias: (document.getElementById('crozzo-prov-edit-banco')?.value || '').trim(),
      representanteLegal: (document.getElementById('crozzo-prov-edit-rep')?.value || '').trim(),
      ciudad: ciudadEdit,
      retenciones: retenciones,
    }),
  };
  if (typeof crozzoReservorioUpsertProveedor === 'function') crozzoReservorioUpsertProveedor(payload);
  else if (typeof CrozzoReservorio !== 'undefined' && CrozzoReservorio.upsertProveedor) {
    CrozzoReservorio.upsertProveedor(payload);
  }
  closeModal();
  showToast('Proveedor actualizado', 'success');
  const mc = document.getElementById('mainContent');
  if (mc && typeof renderComprasProveedores === 'function') {
    const view = (document.getElementById('crozzo-op-root') || {}).getAttribute('data-prov-view') || 'full';
    mc.innerHTML = renderComprasProveedores({ view: view });
    initComprasProveedores({ view: view });
  }
}
function crozzoProvDelete(id) {
  const p = crozzoProvGetFull(id);
  if (!p) return showToast('Proveedor no encontrado', 'error');
  if (
    !confirm(
      '¿Eliminar «' +
        (p.nombre || p.name || id) +
        '» del directorio?\n\nNo borra facturas ya registradas; deja de aparecer en listas nuevas.'
    )
  ) {
    return;
  }
  let ok = false;
  if (typeof CrozzoReservorio !== 'undefined' && CrozzoReservorio.deleteProveedor) {
    ok = CrozzoReservorio.deleteProveedor(id);
  } else {
    const list = (config.get('proveedoresOC') || []).filter((x) => String(x.id) !== String(id));
    config.set('proveedoresOC', list);
    ok = true;
  }
  if (!ok) return showToast('No se pudo eliminar', 'error');
  if (config.addAudit) config.addAudit('proveedor_eliminado', String(p.nombre || id));
  showToast('Proveedor eliminado del directorio', 'success');
  const mc = document.getElementById('mainContent');
  if (mc && typeof renderComprasProveedores === 'function') {
    const view = (document.getElementById('crozzo-op-root') || {}).getAttribute('data-prov-view') || 'full';
    mc.innerHTML = renderComprasProveedores({ view: view });
    initComprasProveedores({ view: view });
  }
}
