function crozzoOpSwitchProvTab(name) {
  const root = document.getElementById('crozzo-op-root');
  if (!root) return;
  const tabs = root.querySelector('#crozzo-op-tabs');
  if (tabs) {
    tabs.querySelectorAll('.crozzo-rep-tab').forEach((t) => {
      t.classList.toggle('active', t.getAttribute('data-op-tab') === name);
    });
  }
  root.querySelectorAll('[data-op-panel]').forEach((panel) => {
    panel.style.display = panel.getAttribute('data-op-panel') === name ? '' : 'none';
  });
}
function crozzoOpBindProvDocImports(root) {
  if (!root) return;
  if (typeof CrozzoProveedorDocumentos === 'undefined' || !CrozzoProveedorDocumentos.bindImportRoot) {
    setTimeout(function () {
      crozzoOpBindProvDocImports(root);
    }, 350);
    return;
  }
  root.querySelectorAll('[data-prov-doc-root]').forEach(function (importRoot) {
    CrozzoProveedorDocumentos.bindImportRoot(importRoot, {
      onSaved: function () {
        const mc = document.getElementById('mainContent');
        const view = (document.getElementById('crozzo-op-root') || {}).getAttribute('data-prov-view') || 'full';
        if (mc && typeof renderComprasProveedores === 'function') {
          mc.innerHTML = renderComprasProveedores({ view: view });
          initComprasProveedores({ view: view });
          if (view === 'full') crozzoOpSwitchProvTab('prov');
        }
      },
    });
  });
}
function initComprasProveedores(opts) {
  opts = opts || {};
  const root = document.getElementById('crozzo-op-root');
  if (!root) return;
  window.__crozzoPoDraft = window.__crozzoPoDraft || [];
  crozzoOpPoRenderDraft();
  const nitLbl = document.getElementById('crozzo-op-prov-nit-label');
  if (nitLbl && typeof CrozzoProveedorDocumentos !== 'undefined' && CrozzoProveedorDocumentos.labelIdentificador) {
    nitLbl.textContent = CrozzoProveedorDocumentos.labelIdentificador();
  }
  crozzoOpBindProvDocImports(root);
  const openTab = window.__crozzoProvOpenTab;
  if (openTab && root.getAttribute('data-prov-view') === 'full') {
    crozzoOpSwitchProvTab(openTab);
    window.__crozzoProvOpenTab = null;
  }
  if (!root.__crozzoOpBound) {
    root.__crozzoOpBound = true;
    root.addEventListener('click', (e) => {
      const tab = e.target.closest('.crozzo-rep-tab');
      if (!tab || !root.contains(tab)) return;
      const name = tab.getAttribute('data-op-tab');
      crozzoOpSwitchProvTab(name);
      if (name === 'import') crozzoOpBindProvDocImports(root);
    });
  }
}
window.crozzoOpSwitchProvTab = crozzoOpSwitchProvTab;
function crozzoOpPoRenderDraft() {
  const el = document.getElementById('crozzo-op-po-draft');
  if (!el) return;
  const d = window.__crozzoPoDraft || [];
  el.innerHTML = d.length
    ? d.map((l) => `<div>${escUserAttr(String(l.nombre || ''))} × ${Number(l.qty) || 0}</div>`).join('')
    : 'Borrador vacío — agrega líneas.';
}
function crozzoOpAddSupplier() {
  crozzoEnsureProveedoresExtensions();
  const name = (document.getElementById('crozzo-op-prov-name')?.value || '').trim();
  if (!name) return showToast('Nombre requerido', 'warning');
  const nitRaw = (document.getElementById('crozzo-op-prov-nit')?.value || '').trim();
  const phone = (document.getElementById('crozzo-op-prov-tel')?.value || '').trim();
  const rubro = (document.getElementById('crozzo-op-prov-rubro')?.value || '').trim();
  let nit = nitRaw;
  if (nitRaw && typeof CrozzoProveedorDocumentos !== 'undefined' && CrozzoProveedorDocumentos.validarIdentificador) {
    const v = CrozzoProveedorDocumentos.validarIdentificador(nitRaw);
    if (v.display) nit = v.display;
    if (v.norm && !v.ok) showToast('Revise el dígito verificador del identificador', 'warning');
  }
  if (typeof crozzoReservorioUpsertProveedor === 'function') {
    crozzoReservorioUpsertProveedor({
      nombre: name,
      nit: nit,
      telefono: phone,
      tipoRubro: rubro,
    });
  } else if (typeof CrozzoReservorio !== 'undefined' && CrozzoReservorio.upsertProveedor) {
    CrozzoReservorio.upsertProveedor({
      nombre: name,
      nit: nit,
      telefono: phone,
      tipoRubro: rubro,
    });
  } else {
    const list = [...(config.get('proveedoresOC') || [])];
    list.push({
      id: 'prov_' + Date.now(),
      name,
      nit,
      phone,
      tipoRubro: rubro,
    });
    config.set('proveedoresOC', list);
  }
  if (config.addAudit) config.addAudit('proveedor_local_agregado', name);
  showToast('Proveedor guardado — visible en Entrada de factura', 'success');
  const mc = document.getElementById('mainContent');
  if (mc) {
    const view = (document.getElementById('crozzo-op-root') || {}).getAttribute('data-prov-view') || 'full';
    mc.innerHTML = renderComprasProveedores({ view: view });
    initComprasProveedores({ view: view });
  }
}
function crozzoOpPoAddLine() {
  if (typeof products === 'undefined' || !Array.isArray(products)) return;
  const pid = document.getElementById('crozzo-op-po-product')?.value;
  const qty = Math.max(1, Number(document.getElementById('crozzo-op-po-qty')?.value) || 1);
  if (!pid) return showToast('Seleccione producto', 'warning');
  const p = products.find((x) => String(x.id) === String(pid));
  if (!p) return showToast('Producto no encontrado', 'warning');
  window.__crozzoPoDraft = window.__crozzoPoDraft || [];
  window.__crozzoPoDraft.push({ productId: p.id, nombre: p.nombre, qty });
  crozzoOpPoRenderDraft();
}
function crozzoOpAddPoLineFromProduct(productId) {
  if (typeof products === 'undefined' || !Array.isArray(products)) return;
  const p = products.find((x) => String(x.id) === String(productId));
  if (!p) return;
  const sel = document.getElementById('crozzo-op-po-product');
  if (sel) sel.value = String(p.id);
  const q = document.getElementById('crozzo-op-po-qty');
  if (q && (!q.value || Number(q.value) < 1)) q.value = String(Math.max(1, (crozzoStockThresholdForProduct(p) || 5) * 2));
  crozzoOpPoAddLine();
}
function crozzoOpPoCreate() {
  crozzoEnsureProveedoresExtensions();
  const supId = document.getElementById('crozzo-op-po-supplier')?.value;
  const list = config.get('proveedoresOC') || [];
  const sup = list.find((s) => String(s.id) === String(supId));
  const draft = window.__crozzoPoDraft || [];
  if (!sup) return showToast('Agregue o seleccione un proveedor', 'warning');
  if (!draft.length) return showToast('Agregue líneas al borrador', 'warning');
  const orders = [...(config.get('ordenesCompra') || [])];
  const id = 'PO-' + String(orders.length + 1).padStart(4, '0');
  orders.push({
    id,
    supplierId: sup.id,
    supplierName: sup.name,
    items: draft.map((x) => ({ ...x })),
    status: 'pendiente',
    date: new Date().toISOString()
  });
  config.set('ordenesCompra', orders);
  window.__crozzoPoDraft = [];
  if (config.addAudit) config.addAudit('orden_compra_creada', id);
  showToast('Orden creada', 'success');
  navigateTo('compras-proveedores');
}
function crozzoOpPOTransit(id) {
  const orders = [...(config.get('ordenesCompra') || [])];
  const po = orders.find((o) => o.id === id);
  if (!po || po.status !== 'pendiente') return;
  po.status = 'transito';
  config.set('ordenesCompra', orders);
  if (config.addAudit) config.addAudit('orden_compra_transito', id);
  showToast('Orden en tránsito', 'info');
  navigateTo('compras-proveedores');
}
function crozzoOpPOReceive(id) {
  if (typeof products === 'undefined' || !Array.isArray(products)) return;
  const orders = [...(config.get('ordenesCompra') || [])];
  const po = orders.find((o) => o.id === id);
  if (!po || po.status !== 'transito') return;
  po.status = 'recibido';
  const touched = new Set();
  (po.items || []).forEach((line) => {
    const idx = products.findIndex((p) => String(p.id) === String(line.productId));
    if (idx < 0) return;
    const p = products[idx];
    const add = Number(line.qty) || 0;
    if (add <= 0) return;
    const cur = p.stock != null && !Number.isNaN(Number(p.stock)) ? Number(p.stock) : null;
    const next = cur == null ? add : cur + add;
    products[idx] = { ...p, stock: next };
    touched.add(p.id);
  });
  config.set('ordenesCompra', orders);
  persistCatalogProductosLocal();
  touched.forEach((pid) => {
    try {
      persistCatalogProductos(pid);
    } catch (_) {}
  });
  if (config.addAudit) config.addAudit('orden_compra_recibida', id);
  try {
    if (window.CrozzoReservorio && CrozzoReservorio.registrarOrdenCompraRecibida) CrozzoReservorio.registrarOrdenCompraRecibida(po);
  } catch (_) {}
  showToast('Mercancía recibida — stock y reservorio actualizados', 'success');
  navigateTo('compras-proveedores');
}
function crozzoOpSetRuntimeMode(m) {
  const modes = ['online', 'hybrid', 'offline'];
  if (!modes.includes(m)) return;
  config.set('runtimeSyncModo', m);
  try {
    window.__crozzoRuntimeSyncMode = m;
  } catch (_) {}
  try {
    document.dispatchEvent(new CustomEvent('crozzo-runtime-sync-mode', { detail: { mode: m } }));
  } catch (_) {}
  if (config.addAudit) config.addAudit('runtime_sync_modo', m);
  showToast('Modo sync: ' + m, 'success');
  navigateTo('compras-proveedores');
}
function crozzoOpRunDiagnostics() {
  const out = document.getElementById('crozzo-op-diag-out');
  if (!out) return;
  let qPending = 0;
  try {
    const raw = localStorage.getItem('crozzo_sync_queue') || localStorage.getItem('sync_queue_temp');
    if (raw) {
      const j = JSON.parse(raw);
      if (Array.isArray(j)) qPending = j.filter((x) => x && (x.status === 'pending' || !x.status)).length;
    }
  } catch (_) {}
  const checks = [
    { n: 'Red', ok: navigator.onLine, msg: navigator.onLine ? 'Online' : 'Sin conexión' },
    { n: 'localStorage', ok: true, msg: (JSON.stringify(localStorage).length / 1024).toFixed(1) + ' KB (aprox.)' },
    { n: 'Cola sync local', ok: qPending < 80, msg: qPending + ' pendientes (aprox.)' },
    { n: 'WebCrypto', ok: !!(window.crypto && crypto.subtle), msg: window.crypto?.subtle ? 'Disponible' : 'Limitado (p. ej. iframe)' }
  ];
  out.innerHTML = checks
    .map(
      (c) => `
    <div class="crozzo-rep-kpi" style="text-align:left;padding:10px;border:1px solid var(--border);border-radius:var(--radius);">
      <div class="lbl">${escUserAttr(c.n)}</div>
      <div class="val" style="font-size:0.95rem;color:${c.ok ? 'var(--success)' : 'var(--warning)'}">${c.ok ? 'OK' : 'Revisar'}</div>
      <div class="form-hint" style="margin-top:4px;">${escUserAttr(c.msg)}</div>
    </div>`
    )
    .join('');
}
