async function __crozzoApplyAdvancedWizardConfig(patch) {
  try {
  if (patch && typeof patch === 'object') {
    wizardState.draft = { ...wizardState.draft, ...patch };
  }
  wizardCommitDraftFromInputs();
  const idemEl = document.getElementById('wzAdvSyncIdempotent');
  if (idemEl) wizardState.draft.syncIdempotent = !!idemEl.checked;
  const roleLocked = wizardState.autoRoleLocked;
  if (!roleLocked) {
    const roleRadio = document.querySelector('input[name="wzRoleTypeAdv"]:checked');
    if (roleRadio) wizardState.role = roleRadio.value === 'B' ? 'B' : 'A';
  }
  const role = wizardState.role === 'B' ? 'B' : 'A';
  for (let s = 1; s <= 4; s++) {
    const v = validateStep(s, role);
    if (!v.ok) {
      showToast(v.message, 'warning');
      if (v.focusId) document.getElementById(v.focusId)?.focus();
      return false;
    }
  }
  const pr = await persistCrozzoLanFromWizardDraft();
  if (!pr.ok) {
    showToast(pr.error === 'loc_mismatch' ? 'El servidor es de otra ubicación (location distinto).' : 'No se pudo guardar LAN.', 'error');
    return false;
  }
  await activateSync();
  await CrozzoAutoConfig.syncRouterStart();
  wizardState.completed = true;
  wizardState.quickAutoFailed = false;
  wizardSaveStoredState({ role: wizardState.role, step: 5, completed: true });
  showToast('✅ Ajustes avanzados guardados.', 'success');
  wizardClose();
  updateCrozzoAutoConfigBadge('ready');
  return true;
  } catch (e) {
    console.warn('[crozzo-advanced-config]', e);
    showToast('Error al guardar configuración avanzada.', 'error');
    return false;
  }
}
