function persistCrozzoSupabaseConfigFileFromMultidispositivo(next) {
  const syncOn = !!next.supabaseSyncEnabled;
  if (syncOn && typeof isSuperAdminUser === 'function' && !isSuperAdminUser()) {
    showToast('Solo el Super Admin puede activar la sincronización con Supabase.', 'warning');
    return false;
  }
  const dm = (document.getElementById('mdCloudDeviceName')?.value || '').trim();
  if (dm) {
    try {
      localStorage.setItem('device_name', dm);
    } catch (e) {
      /* ignore */
    }
  }
  if (!syncOn) {
    try {
      localStorage.removeItem('crozzo_supabase_config');
    } catch (e) {
      /* ignore */
    }
    ['SUPABASE_URL', 'SUPABASE_ANON_KEY', 'supabase_url', 'supabase_anon_key'].forEach((k) => {
      try {
        localStorage.removeItem(k);
      } catch (e) {
        /* ignore */
      }
    });
    next.supabase = { ...next.supabase, url: '', anonKey: '' };
    return true;
  }
  const sbUrl = (next.supabase?.url || '').trim();
  const sbKey = (next.supabase?.anonKey || '').trim();
  if (!sbUrl.toLowerCase().includes('supabase.co')) {
    showToast('La URL de Supabase debe contener "supabase.co"', 'warning');
    document.getElementById('mdSupabaseUrl')?.focus();
    return false;
  }
  if (sbKey.length < 20) {
    showToast('La anon key debe tener al menos 20 caracteres', 'warning');
    document.getElementById('mdSupabaseKey')?.focus();
    return false;
  }
  let devInput = (document.getElementById('mdCloudDeviceIdInput')?.value || '').trim();
  if (!devInput) {
    try {
      devInput = (localStorage.getItem('device_id') || '').trim();
    } catch (e) {
      devInput = '';
    }
  }
  if (!devInput && typeof crypto !== 'undefined' && crypto.randomUUID) {
    devInput = crypto.randomUUID();
    try {
      localStorage.setItem('device_id', devInput);
    } catch (e) {
      /* ignore */
    }
  }
  if (!devInput) devInput = ensureCrozzoDeviceId();
  if (devInput) {
    try {
      localStorage.setItem('device_id', devInput);
    } catch (e) {
      /* ignore */
    }
    next.deviceId = devInput;
  }
  const payload = {
    version: 1,
    syncEnabled: true,
    url: sbUrl,
    anonKey: sbKey,
    deviceName: dm || (() => {
      try {
        return localStorage.getItem('device_name') || '';
      } catch (e) {
        return '';
      }
    })(),
    deviceId: devInput || (() => {
      try {
        return (localStorage.getItem('device_id') || '').trim();
      } catch (e) {
        return '';
      }
    })(),
    savedAt: Date.now(),
  };
  try {
    localStorage.setItem('crozzo_supabase_config', JSON.stringify(payload));
    try {
      document.dispatchEvent(
        new CustomEvent('crozzo-supabase-config-saved', { detail: { url: sbUrl, syncEnabled: true } })
      );
    } catch (_) {}
  } catch (e) {
    showToast('No se pudo guardar la configuración de nube', 'error');
    return false;
  }
  try {
    const idInp = document.getElementById('mdCloudDeviceIdInput');
    if (idInp && payload.deviceId && !String(idInp.value || '').trim()) idInp.value = payload.deviceId;
  } catch (e) {
    /* ignore */
  }
  try {
    if (typeof window.__crozzoSyncStandaloneKeys === 'function') window.__crozzoSyncStandaloneKeys(next);
  } catch (e) {
    console.warn('__crozzoSyncStandaloneKeys', e);
  }
  return true;
}
