function bindMultiStatus() {
  if (!multiSyncRouter) return;
  if (multiStatusUnsubscribe) { try { multiStatusUnsubscribe(); } catch (e) { /* ignore */ } }
  multiStatusUnsubscribe = multiSyncRouter.on('statusChanged', (st) => updateMultiStatusUI(st));
  updateMultiStatusUI(multiSyncRouter.status);
  multiSyncRouter.on('itemSynced', (item) => {
    if (item && item.target) showToast(`Sincronizado vía ${item.target.toUpperCase()}: ${item.type}`, 'success');
  });
  multiSyncRouter.on('itemFailed', (item) => showToast(`Falló: ${item.type} (${item.uuid?.slice(0, 8) || ''})`, 'error'));
}
function updateMultiStatusUI(st) {
  if (!st) return;
  const cloudCard = document.getElementById('mdPriCloud');
  const lanCard = document.getElementById('mdPriLan');
  const offCard = document.getElementById('mdPriOff');
  const cloudMeta = document.getElementById('mdPriCloudMeta');
  const lanMeta = document.getElementById('mdPriLanMeta');
  const offMeta = document.getElementById('mdPriOffMeta');
  const lastBadge = document.getElementById('mdLastTarget');
  const queueCount = document.getElementById('mdQueueCount');
  if (cloudCard) {
    cloudCard.classList.toggle('is-active', st.cloud === 'online');
    cloudCard.classList.toggle('is-down', st.cloud === 'offline');
  }
  if (lanCard) {
    lanCard.classList.toggle('is-active', st.lan === 'online' && st.cloud !== 'online');
    lanCard.classList.toggle('is-down', st.lan === 'offline');
  }
  if (offCard) {
    const offlineActive = st.cloud !== 'online' && st.lan !== 'online';
    offCard.classList.toggle('is-active', offlineActive);
  }
  if (cloudMeta) cloudMeta.textContent = st.cloud === 'online' ? '☁️ Conectado' : st.cloud === 'offline' ? '⚪ Sin nube' : '⏳ Comprobando…';
  if (lanMeta) lanMeta.textContent = st.lan === 'online' ? '📶 LAN viva' : st.lan === 'offline' ? '⚪ LAN inactiva' : '⏳ Comprobando…';
  if (offMeta) offMeta.textContent = st.cloud === 'online' || st.lan === 'online' ? 'Listo como respaldo' : '💾 Guardando local';
  if (lastBadge) {
    lastBadge.className = 'md-target-badge ' + (st.lastTarget || 'offline');
    const map = { cloud: '☁️ Última: Cloud', lan: '📶 Última: LAN', p2p: '🔗 Última: P2P', offline: '💾 Última: Offline' };
    lastBadge.textContent = map[st.lastTarget] || '— sin envíos —';
  }
  if (queueCount) queueCount.textContent = String(st.pending || 0);
}
