function clearMultiQueue() {
  if (!confirm('¿Eliminar todos los items en cola offline? (No afecta los ya sincronizados a la nube)')) return;
  try {
    const req = indexedDB.open('CrozzoMultiSyncDB', 2);
    req.onsuccess = (event) => {
      const db = event.target.result;
      const tx = db.transaction(['mdSyncQueue'], 'readwrite');
      tx.objectStore('mdSyncQueue').clear().onsuccess = () => {
        showToast('Cola offline limpiada', 'success');
        if (multiSyncRouter) {
          multiSyncRouter.queue = [];
          multiSyncRouter._setStatus({ pending: 0 });
        }
        db.close();
      };
    };
  } catch (e) {
    showToast('No se pudo limpiar la cola', 'error');
  }
}
