async function wizardRunStep5Validation() {
  try {
    const tierInfo = window.CrozzoSyncRouterModule && window.CrozzoSyncRouterModule.detectConnectivityTier
      ? await window.CrozzoSyncRouterModule.detectConnectivityTier()
      : await detectConnectivityTier();
    const locOk = !!(wizardState.draft.locationId || '').trim();
    showToast(`Prueba OK · tier=${tierInfo.tier} · location=${locOk ? 'sí' : 'no'}`, locOk ? 'success' : 'warning');
  } catch (e) {
    showToast('No fue posible ejecutar pruebas de conectividad.', 'warning');
  }
}
async function activateSync() {
  wizardCommitDraftFromInputs();
  const d = wizardState.draft;
  const role = wizardState.role === 'B' ? 'B' : 'A';
  const payload = role === 'A'
    ? {
        role: 'A',
        serverIp: (d.serverIp || '').trim(),
        centralIp: '',
        port: Math.max(1, Number(d.port) || 3000),
        mode: d.mode === 'prod' ? 'prod' : 'demo',
        businessName: (d.businessName || '').trim(),
        tabletName: '',
        dianNit: (d.dianNit || '').trim(),
        dianResolution: (d.dianResolution || '').trim(),
        dianRange: (d.dianRange || '').trim(),
        ssidNote: (d.ssidNote || '').trim()
      }
    : {
        role: 'B',
        serverIp: '',
        centralIp: (d.centralIp || '').trim(),
        port: Math.max(1, Number(d.port) || 3000),
        mode: 'demo',
        businessName: '',
        tabletName: (d.tabletName || '').trim(),
        tabletArea: (d.tabletArea || '').trim(),
        ssidNote: (d.ssidNote || '').trim()
      };
  saveWizardConfig(payload);
  try {
    localStorage.setItem('crozzo_sync_prefs', JSON.stringify({
      retentionDays: Number(d.syncRetentionDays) || 30,
      intervalSec: Number(d.syncIntervalSec) || 20,
      priority: d.syncPriority || 'cloud_first',
      idempotent: d.syncIdempotent !== false,
      locationId: d.locationId || '',
      savedAt: Date.now()
    }));
  } catch (e) {
    console.warn('No se pudo guardar preferencias sync', e);
  }
  if (window.CrozzoSyncRouterModule && window.CrozzoSyncRouterModule.refreshConnectivityBadges) {
    try { await window.CrozzoSyncRouterModule.refreshConnectivityBadges(); } catch (e) { /* ignore */ }
  }
  wizardState.completed = true;
  wizardState.quickAutoFailed = false;
  wizardSaveStoredState({ role: payload.role, step: 5, completed: true });
  showToast('Configuración aplicada y sincronización activada.', 'success');
  wizardRender();
}
