function initConfigEmpresa() {
  const nitInput = document.getElementById('cfgNit');
  const dvInput = document.getElementById('cfgDV');
  
  if (nitInput) {
    nitInput.addEventListener('input', (e) => {
      const val = e.target.value;
      const status = document.getElementById('cfgNitStatus');
      if (val.length > 5) {
        const result = validarNIT(val);
        if (result.valido) {
          status.innerHTML = '<span class="form-success">✓ NIT válido</span>';
          nitInput.classList.add('valid');
          nitInput.classList.remove('invalid');
          if (dvInput) dvInput.value = result.dv;
        } else {
          status.innerHTML = `<span class="form-error">✗ ${result.error}</span>`;
          nitInput.classList.add('invalid');
          nitInput.classList.remove('valid');
        }
      } else {
        status.innerHTML = '';
        nitInput.classList.remove('valid', 'invalid');
      }
    });
  }
}
function saveEmpresaConfig() {
  const nitInput = document.getElementById('cfgNit');
  const nitVal = nitInput ? nitInput.value.trim() : '';
  
  if (nitVal) {
    const result = validarNIT(nitVal);
    if (!result.valido) {
      showToast('NIT inválido: ' + result.error, 'error');
      return;
    }
  }
  
  config.set('empresa', {
    nit: nitVal,
    dv: document.getElementById('cfgDV')?.value || '',
    razonSocial: document.getElementById('cfgRazonSocial')?.value || '',
    nombreComercial: document.getElementById('cfgNombreComercial')?.value || '',
    direccion: document.getElementById('cfgDireccion')?.value || '',
    departamento: document.getElementById('cfgDepartamento')?.value || '',
    ciudad: document.getElementById('cfgCiudad')?.value || '',
    telefono: document.getElementById('cfgTelefono')?.value || '',
    email: document.getElementById('cfgEmail')?.value || '',
    codigoPostal: document.getElementById('cfgCodigoPostal')?.value || '',
    regimenFiscal: document.getElementById('cfgRegimen')?.value || 'responsable_iva',
    matriculaMercantil: document.getElementById('cfgMatricula')?.value || '',
    actividadEconomica: document.getElementById('cfgActividad')?.value || ''
  });
  
  config.addAudit('config_empresa_actualizada', 'Datos de empresa actualizados');
  showToast('Configuración de empresa guardada', 'success');
  try {
    if (typeof applyCrozzoBrandingChrome === 'function') applyCrozzoBrandingChrome();
  } catch (_) {}
}
