function crozzoPromptIvaEnPreciosCarta() {
  showModal('Impuesto y precios de carta', `
    <div>
      <p class="form-hint" style="margin-bottom:10px;">¿Los precios que ves en el menú del POS <strong>ya incluyen</strong> IVA o impuesto al consumo?</p>
      <ul style="font-size:0.85rem;color:var(--text-secondary);margin:0 0 14px 20px;line-height:1.45;">
        <li><strong>Sí (incluido):</strong> en la cuenta se muestran neto sin impuesto, impuesto aparte y el total coincide con la suma de precios de línea.</li>
        <li><strong>No:</strong> el impuesto se suma al subtotal (total mayor que solo la suma de netos).</li>
      </ul>
      <div class="btn-group" style="justify-content:center;gap:10px;flex-wrap:wrap;">
        <button type="button" class="btn btn-primary" onclick="crozzoSetIvaIncluidoPrecios(true)">Sí, va incluido</button>
        <button type="button" class="btn btn-outline" onclick="crozzoSetIvaIncluidoPrecios(false)">No, cobrar aparte</button>
      </div>
      <div class="btn-group" style="justify-content:center;margin-top:12px;">
        <button type="button" class="btn btn-outline" onclick="closeModal()">Cerrar</button>
      </div>
    </div>
  `);
}
function crozzoSetIvaIncluidoPrecios(v) {
  const impuestos = crozzoImpuestosNormalize(config.getImpuestos());
  impuestos.ivaIncluidoEnPrecios = !!v;
  config.set('impuestos', impuestos);
  closeModal();
  if (typeof showToast === 'function') {
    showToast(v ? 'Precios tratados como con impuesto incluido en carta.' : 'El impuesto se sumará al total (precio + impuesto).', 'success');
  }
  if (typeof currentPage !== 'undefined') {
    if (currentPage === 'config-impuestos' && typeof renderPage === 'function') renderPage('config-impuestos');
    else if (currentPage === 'cajero' && typeof renderCart === 'function') renderCart();
    else if (currentPage === 'tablets' && typeof renderPage === 'function') renderPage('tablets');
    else if (typeof updateCartTotals === 'function') updateCartTotals();
  }
}
function saveImpuestosConfig() {
  const impuestos = crozzoImpuestosNormalize(config.getImpuestos());
  impuestos.tarifasIVA.forEach((t, i) => {
    const rEl = document.getElementById('taxRate_' + i);
    const dEl = document.getElementById('taxDesc_' + i);
    if (rEl) {
      const pct = parseFloat(rEl.value);
      t.rate = Number.isFinite(pct) ? Math.max(0, Math.min(100, pct)) / 100 : t.rate;
    }
    if (dEl) {
      const d = (dEl.value || '').trim();
      if (d) t.description = d;
    }
  });
  const retFuenteRate = parseFloat(document.getElementById('retFuenteRate')?.value) || 0;
  const retICARate = parseFloat(document.getElementById('retICARate')?.value) || 0;
  impuestos.retencionFuente.tarifa = retFuenteRate / 100;
  impuestos.retencionICA.tarifa = retICARate / 100;
  const cPct = parseFloat(document.getElementById('impConsumoTarifaPct')?.value);
  if (Number.isFinite(cPct)) impuestos.impuestoAlConsumo.tarifa = Math.max(0, Math.min(50, cPct)) / 100;
  config.set('impuestos', impuestos);
  config.addAudit('impuestos_actualizados', 'Configuración de impuestos actualizada');
  showToast('Configuración de impuestos guardada', 'success');
  if (typeof updateCartTotals === 'function') updateCartTotals();
  if (typeof currentPage !== 'undefined' && currentPage === 'tablets' && typeof renderPage === 'function') renderPage('tablets');
}
