// MODO DE OPERACIÓN (Demo / Simple / Electrónica)
// ==========================================
function limpiarFacturasDemoEnHistorial() {
  const fa = config.getFacturas().filter((f) => f.estado !== 'demo' && !f.is_demo);
  config.set('facturas', fa);
  config.save();
  showToast('Facturas marcadas como DEMO eliminadas del historial local.', 'success');
}
function aplicarCambioOperacionModo(nuevo, motivo) {
  const prev = config.getOperacionModo();
  config.setOperacionModo(nuevo);
  config.addAudit('modo_operacion', `Cambio ${prev} → ${nuevo}. ${motivo || ''}`);
  closeModal();
  updateDemoBadge();
  try {
    if (window.CrozzoModeManager) window.__CROZZO_PDF_WATERMARK = CrozzoModeManager.getPdfWatermarkLine();
  } catch (e) { /* ignore */ }
  applyAccessControl();
  let next = currentPage;
  if (pageBlockedByOperacionModo(next)) next = pickFirstAccessiblePage() || 'cajero';
  navigateTo(next);
  showToast('Modo de operación actualizado.', 'success');
}
function requestOperacionModeChange(target) {
  const cur = config.getOperacionModo();
  if (cur === target) {
    showToast('Ese modo ya está activo.', 'info');
    return;
  }
  if (target === 'demo') {
    showModal('🧪 Activar modo DEMO', `
      <div class="fade-in">
        <div class="alert alert-warning" style="margin-bottom:12px;">
          <span>⚠️</span>
          <div><strong>No válido legalmente.</strong> Capacitación y pruebas únicamente. Los comprobantes llevan marca DEMO y el timbrado es simulado (sin DIAN real).</div>
        </div>
        <div class="form-group">
          <label class="form-label">Motivo / responsable (obligatorio)</label>
          <input type="text" class="form-input" id="opModeReason" placeholder="Ej. Capacitación personal mesa">
        </div>
        <div class="btn-group" style="justify-content:flex-end;">
          <button type="button" class="btn btn-outline" onclick="closeModal()">Cancelar</button>
          <button type="button" class="btn btn-warning" onclick="finalizarCambioOperacion('demo')">Activar DEMO</button>
        </div>
      </div>
    `);
    return;
  }
  if (target === 'simple') {
    showModal('💵 Activar facturación SIMPLE', `
      <div class="fade-in">
        <p><strong>Tickets y control de caja.</strong> Documento soporte / recibo de venta según uso interno; <strong>no</strong> es factura electrónica DIAN.</p>
        <p style="font-size:0.85rem;color:var(--text-secondary);margin-top:8px;">Se ocultan DIAN, certificado, proveedor, multi-dispositivo avanzado y auditoría fiscal completa.</p>
        ${cur === 'demo' ? '<p style="font-size:0.85rem;color:var(--warning);margin-top:8px;">Si venías de DEMO, usa el botón «Eliminar ventas DEMO» en esta pantalla antes de auditar cifras reales.</p>' : ''}
        <div class="form-group">
          <label class="form-label">Confirmación (obligatorio)</label>
          <input type="text" class="form-input" id="opModeReason" placeholder="Ej. Negocio pequeño, solo caja">
        </div>
        <div class="btn-group" style="justify-content:flex-end;">
          <button type="button" class="btn btn-outline" onclick="closeModal()">Cancelar</button>
          <button type="button" class="btn btn-primary" onclick="finalizarCambioOperacion('simple')">Activar SIMPLE</button>
        </div>
      </div>
    `);
    return;
  }
  if (target === 'electronic') {
    const v = config.canGoLive();
    const falta = v.missing.length
      ? `<ul style="margin:10px 0;padding-left:18px;font-size:0.88rem;">${v.missing.map((m) => `<li>${m}</li>`).join('')}</ul>`
      : '<p style="font-size:0.88rem;color:var(--success);">Checklist DIAN completo.</p>';
    showModal('🧾 Activar facturación ELECTRÓNICA', `
      <div class="fade-in">
        <p>XML, CUFE, QR y proveedor autorizado. Las ventas con factura electrónica <strong>requieren</strong> configuración válida antes de timbrar.</p>
        ${falta}
        <div class="form-group">
          <label class="form-label">Motivo del cambio (obligatorio)</label>
          <input type="text" class="form-input" id="opModeReason" placeholder="Ej. Obligado DIAN / empresa formal">
        </div>
        <div class="btn-group" style="justify-content:flex-end;flex-wrap:wrap;">
          <button type="button" class="btn btn-outline" onclick="closeModal()">Cancelar</button>
          ${!v.valid ? '<button type="button" class="btn btn-outline" onclick="closeModal(); navigateTo(\'config-dian\');">Ir a configurar DIAN</button>' : ''}
          <button type="button" class="btn btn-success" onclick="finalizarCambioOperacion('electronic')">Activar modo ELECTRÓNICA</button>
        </div>
        <p class="form-hint" style="margin-top:10px;">Puedes activar el modo hoy y completar datos en los menús Super Admin; hasta entonces el cobro en FE puede estar bloqueado.</p>
      </div>
    `);
  }
}
function finalizarCambioOperacion(target) {
  const reason = (document.getElementById('opModeReason')?.value || '').trim();
  if (!reason) {
    showToast('Indica el motivo del cambio.', 'warning');
    return;
  }
  aplicarCambioOperacionModo(target, reason);
}
function renderModoDemo() {
  const modo = config.getOperacionModo();
  const canGo = config.canGoLive();
  const selDemo = modo === 'demo' ? 'border-color:#f97316; background:rgba(249,115,22,0.08);' : '';
  const selSimple = modo === 'simple' ? 'border-color:#3b82f6; background:rgba(59,130,246,0.08);' : '';
  const selElec = modo === 'electronic' ? 'border-color:var(--success); background:rgba(34,197,94,0.1);' : '';
  return `
    <div class="card">
      <div class="card-header">
        <span class="card-title">🔄 Modo de operación</span>
      </div>
      <p class="form-hint" style="margin-bottom:16px;">
        El modo define qué es legalmente válido y qué menús se muestran. Es persistente y reversible con confirmación.
        Modo actual: <strong>${modo === 'demo' ? 'DEMO' : (modo === 'simple' ? 'FACTURACIÓN SIMPLE' : 'FACTURACIÓN ELECTRÓNICA')}</strong>.
      </p>
      <div style="display:grid; grid-template-columns:repeat(auto-fit,minmax(240px,1fr)); gap:14px;">
        <div class="card" style="margin:0; ${selDemo} border:2px solid var(--border);">
          <div style="font-weight:700;margin-bottom:8px;">🧪 Demo</div>
          <p style="font-size:0.82rem;color:var(--text-secondary);margin:0 0 12px;">Pruebas, capacitación. <strong>No válido.</strong> Timbrado simulado.</p>
          <button type="button" class="btn btn-outline" style="width:100%;" onclick="requestOperacionModeChange('demo')">Usar modo DEMO</button>
        </div>
        <div class="card" style="margin:0; ${selSimple} border:2px solid var(--border);">
          <div style="font-weight:700;margin-bottom:8px;">💵 Facturación simple</div>
          <p style="font-size:0.82rem;color:var(--text-secondary);margin:0 0 12px;">Caja, tickets, inventario básico. Válido como soporte interno; <strong>no</strong> FE DIAN.</p>
          <button type="button" class="btn btn-outline" style="width:100%;" onclick="requestOperacionModeChange('simple')">Usar modo SIMPLE</button>
        </div>
        <div class="card" style="margin:0; ${selElec} border:2px solid var(--border);">
          <div style="font-weight:700;margin-bottom:8px;">🧾 Facturación electrónica</div>
          <p style="font-size:0.82rem;color:var(--text-secondary);margin:0 0 12px;">Resolución DIAN, certificado, proveedor, multi-dispositivo, auditoría.</p>
          <button type="button" class="btn btn-outline" style="width:100%;" onclick="requestOperacionModeChange('electronic')">Usar modo ELECTRÓNICA</button>
        </div>
      </div>
      <div class="card" style="margin-top:18px; background:var(--bg-primary);">
        <div class="card-title" style="margin-bottom:10px;">📋 Checklist para timbrado electrónico válido</div>
        <ul class="checklist" style="margin:0;">
          ${canGo.missing.map((m) => `<li><span class="check-icon fail">✗</span><span>${m}</span></li>`).join('')}
          ${canGo.missing.length === 0 ? '<li><span class="check-icon pass">✓</span><span>Listo para emitir FE (según proveedor)</span></li>' : ''}
        </ul>
      </div>
      <div class="btn-group" style="margin-top:14px;">
        <button type="button" class="btn btn-outline" onclick="limpiarFacturasDemoEnHistorial()">🧹 Eliminar del historial las ventas DEMO (simuladas)</button>
      </div>
    </div>
  `;
}
function initModoDemo() {}
