// Super Admin — Identidad y logos (dual branding)
// ==========================================
window.__crozzoIdentidadPending = window.__crozzoIdentidadPending || { platform: null, tenant: null };
function crozzoIdentidadEscAttr(s) {
  return String(s || '')
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}
function crozzoIdentidadEscMini(s) {
  return String(s || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}
function crozzoIdentidadReadUrlForPreview(which) {
  var b = getCrozzoBranding();
  var pend = window.__crozzoIdentidadPending || {};
  if (which === 'platform') return pend.platform != null ? pend.platform : String((b.platform && b.platform.dataUrl) || '');
  return pend.tenant != null ? pend.tenant : String((b.tenant && b.tenant.dataUrl) || '');
}
function crozzoIdentidadLetNum(id, fallback) {
  var el = document.getElementById(id);
  if (!el) return fallback;
  var n = parseInt(el.value, 10);
  return isNaN(n) ? fallback : n;
}
function crozzoIdentidadViewFieldId(zone, side, field) {
  var z = { sidebar: 'Sb', header: 'Hd', login: 'Lg' }[zone] || 'Sb';
  var s = side === 'tenant' ? 'T' : 'P';
  var f = { fit: 'Fit', scale: 'Scale', focusX: 'Fx', focusY: 'Fy' }[field] || 'Fit';
  return 'idView' + z + s + f;
}
function crozzoIdentidadReadViewFromForm(zone, side, fallback) {
  var fitEl = document.getElementById(crozzoIdentidadViewFieldId(zone, side, 'fit'));
  var scaleEl = document.getElementById(crozzoIdentidadViewFieldId(zone, side, 'scale'));
  var fxEl = document.getElementById(crozzoIdentidadViewFieldId(zone, side, 'focusX'));
  var fyEl = document.getElementById(crozzoIdentidadViewFieldId(zone, side, 'focusY'));
  var fb = fallback || crozzoDefaultSlotView('contain');
  var scale = scaleEl ? parseInt(scaleEl.value, 10) : fb.scale;
  if (isNaN(scale)) scale = fb.scale;
  var fx = fxEl ? parseInt(fxEl.value, 10) : fb.focusX;
  if (isNaN(fx)) fx = fb.focusX;
  var fy = fyEl ? parseInt(fyEl.value, 10) : fb.focusY;
  if (isNaN(fy)) fy = fb.focusY;
  return {
    objectFit: fitEl && fitEl.value === 'cover' ? 'cover' : 'contain',
    scale: Math.min(CROZZO_BRAND_VIEW_SCALE_MAX, Math.max(CROZZO_BRAND_VIEW_SCALE_MIN, scale)),
    focusX: Math.min(100, Math.max(0, fx)),
    focusY: Math.min(100, Math.max(0, fy))
  };
}
function crozzoIdentidadViewControlsHtml(zoneKey, zoneLabel, side, view, globalFit) {
  var idFit = crozzoIdentidadViewFieldId(zoneKey, side, 'fit');
  var idScale = crozzoIdentidadViewFieldId(zoneKey, side, 'scale');
  var idFx = crozzoIdentidadViewFieldId(zoneKey, side, 'focusX');
  var idFy = crozzoIdentidadViewFieldId(zoneKey, side, 'focusY');
  var v = view || crozzoDefaultSlotView(globalFit);
  var fit = v.objectFit || globalFit || 'contain';
  var sideLabel = side === 'tenant' ? 'negocio' : 'plataforma';
  return (
    '<div class="crozzo-identidad-view-block">' +
    '<div class="crozzo-identidad-view-caption">' +
    zoneLabel +
    ' · ' +
    sideLabel +
    '</div>' +
    '<div class="form-group"><label class="form-label">Encaje</label><select class="form-select crozzo-identidad-select" id="' +
    idFit +
    '"><option value="contain"' +
    (fit === 'cover' ? '' : ' selected') +
    '>Ver completa</option><option value="cover"' +
    (fit === 'cover' ? ' selected' : '') +
    '>Rellenar</option></select></div>' +
    '<div class="form-group"><label class="form-label">Escala (' +
    v.scale +
    '%)</label><input type="range" class="crozzo-identidad-range" id="' +
    idScale +
    '" min="' +
    CROZZO_BRAND_VIEW_SCALE_MIN +
    '" max="' +
    CROZZO_BRAND_VIEW_SCALE_MAX +
    '" step="1" value="' +
    v.scale +
    '"><input type="number" class="form-input crozzo-identidad-range-num" data-range-for="' +
    idScale +
    '" min="' +
    CROZZO_BRAND_VIEW_SCALE_MIN +
    '" max="' +
    CROZZO_BRAND_VIEW_SCALE_MAX +
    '" value="' +
    v.scale +
    '" style="max-width:88px;margin-top:6px;"></div>' +
    '<div class="form-group"><label class="form-label">Enfoque horizontal (' +
    v.focusX +
    '%)</label><input type="range" class="crozzo-identidad-range" id="' +
    idFx +
    '" min="0" max="100" step="1" value="' +
    v.focusX +
    '"></div>' +
    '<div class="form-group"><label class="form-label">Enfoque vertical (' +
    v.focusY +
    '%)</label><input type="range" class="crozzo-identidad-range" id="' +
    idFy +
    '" min="0" max="100" step="1" value="' +
    v.focusY +
    '"></div>' +
    '</div>'
  );
}
function crozzoIdentidadPaintPvCell(el, show, url, w, h, emoji, label, viewOpts, logoOnly) {
  if (!el) return;
  if (!show) {
    el.classList.remove('is-on');
    el.innerHTML = '';
    return;
  }
  el.classList.add('is-on');
  var sc = 0.52;
  var ww = Math.max(22, Math.round(w * sc));
  var hh = Math.max(22, Math.round(h * sc));
  el.style.width = ww + 'px';
  el.style.height = hh + 'px';
  var v = viewOpts || crozzoDefaultSlotView('contain');
  var pos = v.focusX + '% ' + v.focusY + '%';
  el.style.setProperty('--pv-fit', v.objectFit === 'cover' ? 'cover' : 'contain');
  el.style.setProperty('--pv-pos', pos);
  el.style.setProperty('--pv-scale', String((v.scale || 100) / 100));
  var has = typeof crozzoBrandHasImageSrc === 'function' ? crozzoBrandHasImageSrc(url) : !!(url && String(url).trim().length > 40);
  if (has) {
    el.innerHTML = '<img alt="" src="' + crozzoIdentidadEscAttr(url) + '" />';
  } else if (logoOnly) {
    el.innerHTML =
      '<div class="crozzo-identidad-pv-fallback crozzo-identidad-pv-fallback--icon"><span>' +
      crozzoIdentidadEscMini(emoji) +
      '</span></div>';
  } else {
    el.innerHTML =
      '<div class="crozzo-identidad-pv-fallback"><span>' +
      crozzoIdentidadEscMini(emoji) +
      '</span><span>' +
      crozzoIdentidadEscMini(label) +
      '</span></div>';
  }
}
function crozzoIdentidadFillStage(stageId, url, viewOpts) {
  var st = document.getElementById(stageId);
  if (!st) return;
  var v = viewOpts || crozzoDefaultSlotView('contain');
  var f = v.objectFit === 'cover' ? 'cover' : 'contain';
  var pos = v.focusX + '% ' + v.focusY + '%';
  var scale = (v.scale || 100) / 100;
  var has = typeof crozzoBrandHasImageSrc === 'function' ? crozzoBrandHasImageSrc(url) : !!(url && String(url).trim().length > 40);
  if (has) {
    st.innerHTML =
      '<img alt="Vista previa logo" src="' +
      crozzoIdentidadEscAttr(url) +
      '" style="max-width:100%;max-height:min(420px,55vh);object-fit:' +
      crozzoIdentidadEscAttr(f) +
      ';object-position:' +
      crozzoIdentidadEscAttr(pos) +
      ';transform:scale(' +
      scale +
      ');transform-origin:' +
      crozzoIdentidadEscAttr(pos) +
      ';" />';
  } else {
    st.innerHTML =
      '<span class="form-hint" style="text-align:center;padding:16px;">Aquí verás el logo al subir un archivo</span>';
  }
}
function crozzoIdentidadRefreshPreview() {
  var root = document.getElementById('crozzoIdentidadRoot');
  if (!root) return;
  var b = getCrozzoBranding();
  var sz = b.sizes || getDefaultCrozzoBranding().sizes;
  var sh = crozzoIdentidadReadShowFromForm(b);
  var platUrl = crozzoIdentidadReadUrlForPreview('platform');
  if (!platUrl && typeof crozzoResolvePlatformBranding === 'function') {
    platUrl = (crozzoResolvePlatformBranding(b.platform || {}).dataUrl) || '';
  }
  var tenUrl = crozzoIdentidadReadUrlForPreview('tenant');
  var platLabel = (document.getElementById('idPlatLabel') && document.getElementById('idPlatLabel').value) || (b.platform && b.platform.label) || 'BONA origen';
  var tenLabel = (document.getElementById('idTenantLabel') && document.getElementById('idTenantLabel').value.trim()) || '';
  if (!tenLabel) {
    try {
      if (typeof config !== 'undefined' && config.getEmpresa) {
        var em = config.getEmpresa() || {};
        tenLabel = em.nombreComercial || em.razonSocial || 'Tu negocio';
      } else {
        tenLabel = 'Tu negocio';
      }
    } catch (e) {
      tenLabel = 'Tu negocio';
    }
  }
  var pe = (document.getElementById('idPlatEmoji') && document.getElementById('idPlatEmoji').value) || (b.platform && b.platform.emoji) || '🧾';
  var ple = (document.getElementById('idPlatLoginEmoji') && document.getElementById('idPlatLoginEmoji').value) || (b.platform && b.platform.loginEmoji) || '✨';
  var te = (document.getElementById('idTenantEmoji') && document.getElementById('idTenantEmoji').value) || (b.tenant && b.tenant.emoji) || '🏪';
  var platFitEl = document.getElementById('idPlatFit');
  var tenFitEl = document.getElementById('idTenantFit');
  var platFit = (platFitEl && platFitEl.value) || (b.platform && b.platform.objectFit) || 'contain';
  var tenFit = (tenFitEl && tenFitEl.value) || (b.tenant && b.tenant.objectFit) || 'contain';
  var views = b.views || getDefaultCrozzoBrandingViews();
  var vSbP = crozzoIdentidadReadViewFromForm('sidebar', 'platform', views.sidebar && views.sidebar.platform);
  var vSbT = crozzoIdentidadReadViewFromForm('sidebar', 'tenant', views.sidebar && views.sidebar.tenant);
  var vHdP = crozzoIdentidadReadViewFromForm('header', 'platform', views.header && views.header.platform);
  var vHdT = crozzoIdentidadReadViewFromForm('header', 'tenant', views.header && views.header.tenant);
  var vLgP = crozzoIdentidadReadViewFromForm('login', 'platform', views.login && views.login.platform);
  var vLgT = crozzoIdentidadReadViewFromForm('login', 'tenant', views.login && views.login.tenant);
  crozzoIdentidadFillStage('idPlatStage', platUrl, vSbP);
  crozzoIdentidadFillStage('idTenantStage', tenUrl, vSbT);
  var sbPw = crozzoIdentidadLetNum('idSzSbPw', sz.sidebar.pw);
  var sbPh = crozzoIdentidadLetNum('idSzSbPh', sz.sidebar.ph);
  var sbTw = crozzoIdentidadLetNum('idSzSbTw', sz.sidebar.tw);
  var sbTh = crozzoIdentidadLetNum('idSzSbTh', sz.sidebar.th);
  var hdPw = crozzoIdentidadLetNum('idSzHdPw', sz.header.pw);
  var hdPh = crozzoIdentidadLetNum('idSzHdPh', sz.header.ph);
  var hdTw = crozzoIdentidadLetNum('idSzHdTw', sz.header.tw);
  var hdTh = crozzoIdentidadLetNum('idSzHdTh', sz.header.th);
  var lgPw = crozzoIdentidadLetNum('idSzLgPw', sz.login.pw);
  var lgPh = crozzoIdentidadLetNum('idSzLgPh', sz.login.ph);
  var lgTw = crozzoIdentidadLetNum('idSzLgTw', sz.login.tw);
  var lgTh = crozzoIdentidadLetNum('idSzLgTh', sz.login.th);
  crozzoIdentidadPaintPvCell(document.getElementById('idPvSbPlat'), sh.sidebar.platform, platUrl, sbPw, sbPh, pe, platLabel, vSbP, true);
  crozzoIdentidadPaintPvCell(document.getElementById('idPvHdPlat'), sh.header.platform, platUrl, hdPw, hdPh, pe, platLabel, vHdP, true);
  crozzoIdentidadPaintPvCell(document.getElementById('idPvHdTen'), sh.header.tenant, tenUrl, hdTw, hdTh, te, tenLabel, vHdT, true);
  crozzoIdentidadPaintPvCell(document.getElementById('idPvLgPlat'), sh.login.platform, platUrl, lgPw, lgPh, ple, platLabel, vLgP, false);
  crozzoIdentidadPaintPvCell(document.getElementById('idPvLgTen'), sh.login.tenant, tenUrl, lgTw, lgTh, te, tenLabel, vLgT, false);
}
function crozzoIdentidadReadShowFromForm(b) {
  var d = getDefaultCrozzoBranding().show;
  function z(idp, idt, def) {
    var ep = document.getElementById(idp);
    var et = document.getElementById(idt);
    return {
      platform: ep ? !!ep.checked : def.platform,
      tenant: et ? !!et.checked : def.tenant
    };
  }
  var sidebar = z('idShSbP', 'idShSbT', d.sidebar);
  sidebar.tenant = false;
  return {
    sidebar: sidebar,
    header: z('idShHdP', 'idShHdT', d.header),
    login: z('idShLgP', 'idShLgT', d.login)
  };
}
window.crozzoIdentidadRefreshPreview = crozzoIdentidadRefreshPreview;
function crozzoBuildMenuCatalogCheckboxes(prefix, checkedMap, disabled) {
  var html = '';
  var dis = disabled ? ' disabled' : '';
  CROZZO_MENU_CATALOG.forEach(function (grp) {
    html += '<div class="crozzo-menu-catalog-group" style="margin-bottom:14px;">';
    html += '<h4 style="margin:0 0 8px;font-size:0.85rem;color:var(--text-secondary);">' + grp.group + '</h4>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:8px;">';
    grp.items.forEach(function (it) {
      var on = checkedMap && checkedMap[it.id] ? ' checked' : '';
      html +=
        '<label style="display:flex;gap:8px;align-items:center;font-size:0.875rem;">' +
        '<input type="checkbox" ' +
        prefix +
        ' data-menu="' +
        it.id +
        '"' +
        on +
        dis +
        '> ' +
        (it.icon || '') +
        ' ' +
        it.label +
        '</label>';
    });
    html += '</div></div>';
  });
  return html;
}
function crozzoBuildRoleMenusCheckboxes(client) {
  var html = '<div class="role-menus" style="display:flex;flex-direction:column;gap:20px;">';
  CROZZO_ROLES_MENU_CONFIG.forEach(function (roleDef) {
    var roleState = (client.roles && client.roles[roleDef.id]) || {};
    var defaults = roleDef.defaults || {};
    html += '<div class="card" style="padding:16px;background:var(--bg-primary);">';
    html += '<h4 style="margin:0 0 10px;">' + roleDef.label + '</h4>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:8px;">';
    CROZZO_MENU_CATALOG.forEach(function (grp) {
      grp.items.forEach(function (it) {
        var checked = roleState[it.id] !== undefined ? !!roleState[it.id] : !!defaults[it.id];
        html +=
          '<label style="display:flex;gap:8px;align-items:center;font-size:0.85rem;">' +
          '<input type="checkbox" data-role="' +
          roleDef.id +
          '" data-menu="' +
          it.id +
          '"' +
          (checked ? ' checked' : '') +
          '> ' +
          (it.icon || '') +
          ' ' +
          it.label +
          '</label>';
      });
    });
    html += '</div></div>';
  });
  html +=
    '<div class="card" style="padding:16px;opacity:0.9;">' +
    '<h4 style="margin:0 0 8px;">🔒 Super Admin</h4>' +
    '<p class="form-hint" style="margin:0;">Siempre ve todos los módulos y la configuración de plataforma (DIAN, certificado, identidad, etc.).</p></div>';
  html += '</div>';
  return html;
}
function renderGestionPerfilesMenus() {
  var cfg = crozzoLoadMenuProfilesConfig();
  var clientIds = Object.keys(cfg.clients || {});
  var activeId = cfg.activeClientId || 'default';
  var clientOpts = clientIds
    .map(function (id) {
      var c = cfg.clients[id];
      var sel = id === activeId ? ' selected' : '';
      return '<option value="' + id + '"' + sel + '>' + (c.nombre || id) + '</option>';
    })
    .join('');
  var themeOpts = CROZZO_THEME_MODELS.map(function (t) {
    return '<option value="' + t.id + '">' + t.label + '</option>';
  }).join('');
  var activeClient = cfg.clients[activeId] || cfg.clients.default;
  var menuChecks = crozzoBuildMenuCatalogCheckboxes('data-client-menu', activeClient.menus || {}, false);
  return (
    '<section id="gestion-perfiles" class="menu-section">' +
    '<div class="card">' +
    '<h2 style="margin-top:0;">📋 Gestión de Perfiles, Clientes y Menús</h2>' +
    '<p class="form-hint" style="margin:0;">Elige un <strong>cliente</strong> (negocio), define qué módulos puede ver y el <strong>modelo visual</strong>. Los usuarios solo verán menús permitidos para ese cliente y su rol.</p>' +
    '</div>' +
    '<div class="card" style="margin-top:14px;">' +
    '<h3 style="margin-top:0;">🏢 Cliente / Negocio</h3>' +
    '<div class="form-grid" style="grid-template-columns:1fr auto auto;gap:12px;align-items:end;max-width:720px;">' +
    '<div class="form-group"><label class="form-label">Cliente activo</label>' +
    '<select id="crozzo-cliente-select" class="form-select">' +
    clientOpts +
    '</select></div>' +
    '<button type="button" class="btn btn-outline" id="crozzo-cliente-nuevo">➕ Nuevo</button>' +
    '<button type="button" class="btn btn-outline" id="crozzo-cliente-renombrar">✏️ Renombrar</button>' +
    '</div>' +
    '<p class="form-hint" id="crozzo-cliente-hint" style="margin-top:10px;">ID: <code>' +
    activeId +
    '</code></p></div>' +
    '<div class="card" style="margin-top:14px;">' +
    '<h3 style="margin-top:0;">🎨 Modelo visual (tema)</h3>' +
    '<p class="form-hint">Apariencia que verá este cliente al usar la app.</p>' +
    '<select id="crozzo-cliente-tema" class="form-select" style="max-width:420px;">' +
    themeOpts +
    '</select></div>' +
    '<div class="card" style="margin-top:14px;">' +
    '<h3 style="margin-top:0;">📦 Perfil de empresa</h3>' +
    '<select id="perfil-empresa-select" class="form-select" style="max-width:420px;">' +
    '<option value="completo">Completo (todos los módulos)</option>' +
    '<option value="restaurante">Restaurante (mesas, comandas, cocina)</option>' +
    '<option value="retail">Retail / Tienda (venta comercial)</option>' +
    '<option value="servicios">Servicios / Mostrador (venta comercial)</option>' +
    '<option value="basico">Básico (solo venta comercial)</option>' +
    '<option value="personalizado">Personalizado (marcar módulos abajo)</option>' +
    '</select>' +
    '<p class="form-hint" style="margin-top:8px;">Con <em>Personalizado</em> usa la lista de módulos permitidos. Con otros perfiles, los roles se limitan dentro de ese conjunto.</p>' +
    '</div>' +
    '<div class="card" style="margin-top:14px;" id="crozzo-cliente-menus-card">' +
    '<h3 style="margin-top:0;">📂 Módulos visibles para este cliente</h3>' +
    '<p class="form-hint">Marca lo que este negocio puede usar (regla 60-30-10: solo lo esencial).</p>' +
    '<div id="crozzo-cliente-menus-list">' +
    menuChecks +
    '</div></div>' +
    '<div class="card" style="margin-top:14px;">' +
    '<h3 style="margin-top:0;">🔐 Menús por rol (dentro del cliente)</h3>' +
    '<p class="form-hint">Restringe aún más según el rol del usuario.</p>' +
    '<div id="crozzo-role-menus-wrap">' +
    crozzoBuildRoleMenusCheckboxes(activeClient) +
    '</div></div>' +
    '<div style="display:flex;flex-wrap:wrap;gap:10px;margin-top:16px;">' +
    '<button type="button" id="guardar-perfil-menus" class="btn btn-primary">💾 Guardar configuración</button>' +
    '<button type="button" id="crozzo-cliente-aplicar-tema" class="btn btn-outline">🎨 Aplicar modelo ahora</button>' +
    '<button type="button" id="crozzo-cliente-eliminar" class="btn btn-outline" style="color:var(--danger);">🗑️ Eliminar cliente</button>' +
    '</div></section>'
  );
}
function crozzoGestionPerfilesRefreshUI() {
  var root = document.getElementById('gestion-perfiles');
  if (!root || !root.parentElement) return;
  var parent = root.parentElement;
  var html = renderGestionPerfilesMenus();
  var wrap = document.createElement('div');
  wrap.innerHTML = html;
  var newSec = wrap.firstElementChild;
  if (newSec) {
    parent.replaceChild(newSec, root);
    initGestionPerfilesMenus();
  }
}
function initGestionPerfilesMenus() {
  var cfg = crozzoLoadMenuProfilesConfig();
  var activeId = cfg.activeClientId || 'default';
  var client = cfg.clients[activeId] || cfg.clients.default;
  var selCliente = document.getElementById('crozzo-cliente-select');
  var selPerfil = document.getElementById('perfil-empresa-select');
  var selTema = document.getElementById('crozzo-cliente-tema');
  var btnSave = document.getElementById('guardar-perfil-menus');
  var btnTema = document.getElementById('crozzo-cliente-aplicar-tema');
  var btnNuevo = document.getElementById('crozzo-cliente-nuevo');
  var btnRen = document.getElementById('crozzo-cliente-renombrar');
  var btnDel = document.getElementById('crozzo-cliente-eliminar');
  var menusCard = document.getElementById('crozzo-cliente-menus-card');
  function toggleMenusCard() {
    var p = selPerfil ? selPerfil.value : 'completo';
    if (menusCard) menusCard.style.display = p === 'personalizado' ? '' : 'none';
  }
  if (selPerfil) {
    selPerfil.value = client.perfil || 'completo';
    if (!selPerfil._crozzoPerfilChg) {
      selPerfil._crozzoPerfilChg = true;
      selPerfil.addEventListener('change', toggleMenusCard);
    }
    toggleMenusCard();
  }
  if (selTema) selTema.value = client.tema || 'executive-elite';
  if (selCliente && !selCliente._crozzoClienteBound) {
    selCliente._crozzoClienteBound = true;
    selCliente.addEventListener('change', function () {
      cfg.activeClientId = selCliente.value;
      crozzoSaveMenuProfilesConfig(cfg);
      crozzoGestionPerfilesRefreshUI();
      if (typeof showToast === 'function') showToast('Cliente activo: ' + (cfg.clients[cfg.activeClientId].nombre || cfg.activeClientId), 'info');
      crozzoApplyActiveClientTheme();
      if (typeof crozzoRebuildMenusFromRoles === 'function') crozzoRebuildMenusFromRoles();
    });
  }
  if (btnNuevo && !btnNuevo._bound) {
    btnNuevo._bound = true;
    btnNuevo.addEventListener('click', function () {
      var nombre = prompt('Nombre del nuevo cliente / negocio:', 'Nuevo negocio');
      if (!nombre || !nombre.trim()) return;
      var id = 'cli_' + Date.now().toString(36);
      cfg.clients[id] = {
        id: id,
        nombre: nombre.trim(),
        perfil: 'basico',
        tema: 'executive-elite',
        menus: { 'punto-venta': true, caja: true },
        roles: { user: { 'punto-venta': true, caja: true }, admin: {}, mesero: {} }
      };
      cfg.activeClientId = id;
      crozzoSaveMenuProfilesConfig(cfg);
      crozzoGestionPerfilesRefreshUI();
      if (typeof showToast === 'function') showToast('Cliente creado', 'success');
    });
  }
  if (btnRen && !btnRen._bound) {
    btnRen._bound = true;
    btnRen.addEventListener('click', function () {
      var c = cfg.clients[cfg.activeClientId];
      if (!c) return;
      var nombre = prompt('Nuevo nombre del cliente:', c.nombre || '');
      if (!nombre || !nombre.trim()) return;
      c.nombre = nombre.trim();
      crozzoSaveMenuProfilesConfig(cfg);
      crozzoGestionPerfilesRefreshUI();
    });
  }
  if (btnDel && !btnDel._bound) {
    btnDel._bound = true;
    btnDel.addEventListener('click', function () {
      if (cfg.activeClientId === 'default') {
        if (typeof showToast === 'function') showToast('No se puede eliminar el cliente principal', 'warning');
        return;
      }
      if (!confirm('¿Eliminar este cliente y su configuración de menús?')) return;
      delete cfg.clients[cfg.activeClientId];
      cfg.activeClientId = 'default';
      crozzoSaveMenuProfilesConfig(cfg);
      crozzoGestionPerfilesRefreshUI();
      if (typeof crozzoRebuildMenusFromRoles === 'function') crozzoRebuildMenusFromRoles();
    });
  }
  if (btnTema && !btnTema._bound) {
    btnTema._bound = true;
    btnTema.addEventListener('click', function () {
      var c2 = cfg.clients[cfg.activeClientId] || cfg.clients.default;
      if (selTema && c2) c2.tema = selTema.value;
      crozzoSaveMenuProfilesConfig(cfg);
      crozzoApplyActiveClientTheme();
      if (typeof showToast === 'function') showToast('Modelo visual aplicado', 'success');
    });
  }
  if (btnSave && !btnSave._crozzoPerfilBound) {
    btnSave._crozzoPerfilBound = true;
    btnSave.addEventListener('click', function () {
      cfg = crozzoLoadMenuProfilesConfig();
      var c = cfg.clients[cfg.activeClientId] || cfg.clients.default;
      c.perfil = selPerfil ? selPerfil.value : 'completo';
      c.tema = selTema ? selTema.value : 'executive-elite';
      c.menus = {};
      document.querySelectorAll('#gestion-perfiles input[data-client-menu][data-menu]').forEach(function (cb) {
        c.menus[cb.getAttribute('data-menu')] = cb.checked;
      });
      c.roles = { user: {}, admin: {}, mesero: {} };
      document.querySelectorAll('#gestion-perfiles input[data-role][data-menu]').forEach(function (cb) {
        var role = cb.getAttribute('data-role');
        var menu = cb.getAttribute('data-menu');
        if (!c.roles[role]) c.roles[role] = {};
        c.roles[role][menu] = cb.checked;
      });
      crozzoSaveMenuProfilesConfig(cfg);
      crozzoApplyActiveClientTheme();
      if (typeof showToast === 'function') showToast('Configuración guardada para «' + (c.nombre || cfg.activeClientId) + '»', 'success');
      if (typeof crozzoRebuildMenusFromRoles === 'function') crozzoRebuildMenusFromRoles();
    });
  }
}
window.crozzoLoadMenuProfilesConfig = crozzoLoadMenuProfilesConfig;
window.crozzoGetActiveClientProfile = crozzoGetActiveClientProfile;
window.crozzoApplyActiveClientTheme = crozzoApplyActiveClientTheme;
