function crozzoIdentidadApplyPreset(code) {
  var cur = getCrozzoBranding();
  var show;
  if (code === 'both') {
    show = {
      sidebar: { platform: true, tenant: true },
      header: { platform: true, tenant: true },
      login: { platform: true, tenant: true }
    };
  } else if (code === 'split') {
    show = {
      login: { platform: true, tenant: false },
      sidebar: { platform: false, tenant: true },
      header: { platform: false, tenant: true }
    };
  } else if (code === 'split_inv') {
    show = {
      login: { platform: false, tenant: true },
      sidebar: { platform: true, tenant: false },
      header: { platform: true, tenant: false }
    };
  } else if (code === 'only_platform') {
    show = {
      sidebar: { platform: true, tenant: false },
      header: { platform: true, tenant: false },
      login: { platform: true, tenant: false }
    };
  } else if (code === 'only_tenant') {
    show = {
      sidebar: { platform: false, tenant: true },
      header: { platform: false, tenant: true },
      login: { platform: false, tenant: true }
    };
  } else {
    return;
  }
  var merged = crozzoSanitizeBrandingBundle(crozzoMergeIdentidad(cur, { show: show }));
  try {
    localStorage.setItem(CROZZO_BRANDING_LS_KEY, JSON.stringify(merged));
  } catch (e) {
    if (typeof showToast === 'function') showToast('No se pudo guardar la disposición', 'error');
    return;
  }
  applyCrozzoBrandingChrome();
  if (typeof showToast === 'function') showToast('Disposición de logos actualizada', 'success');
  if (typeof config !== 'undefined' && config.addAudit) {
    try {
      config.addAudit('identidad_preset', 'Preset logos: ' + String(code));
    } catch (e2) {
      /* ignore */
    }
  }
  navigateTo('super-admin-identidad');
}
function crozzoIdentidadClearImage(which) {
  var b = getCrozzoBranding();
  if (which === 'platform') {
    b.platform.dataUrl = getDefaultCrozzoBranding().platform.dataUrl;
    if (window.__crozzoIdentidadPending) window.__crozzoIdentidadPending.platform = null;
    var f = document.getElementById('idPlatFile');
    if (f) f.value = '';
  } else {
    b.tenant.dataUrl = '';
    if (window.__crozzoIdentidadPending) window.__crozzoIdentidadPending.tenant = null;
    var f2 = document.getElementById('idTenantFile');
    if (f2) f2.value = '';
  }
  localStorage.setItem(CROZZO_BRANDING_LS_KEY, JSON.stringify(crozzoSanitizeBrandingBundle(b)));
  applyCrozzoBrandingChrome();
  if (typeof showToast === 'function') showToast(which === 'platform' ? 'Logo BONA restaurado' : 'Imagen eliminada', 'success');
  navigateTo('super-admin-identidad');
}
function crozzoIdentidadResetDefaults() {
  try {
    localStorage.removeItem(CROZZO_BRANDING_LS_KEY);
    localStorage.setItem(CROZZO_BRANDING_BONA_MIG_KEY, '1');
    localStorage.setItem(CROZZO_BRANDING_BONA_V3_PROP_KEY, '1');
    localStorage.setItem(CROZZO_BRANDING_BONA_V4_SIDEBAR_KEY, '1');
  } catch (e) {
    /* ignore */
  }
  window.__crozzoIdentidadPending = { platform: null, tenant: null };
  applyCrozzoBrandingChrome();
  if (typeof showToast === 'function') showToast('Identidad restaurada a valores por defecto', 'success');
  if (typeof config !== 'undefined' && config.addAudit) {
    try {
      config.addAudit('identidad_reset', 'Identidad BONA restaurada a predeterminados');
    } catch (e2) {
      /* ignore */
    }
  }
  navigateTo('super-admin-identidad');
}
function crozzoIdentidadSave() {
  var cur = getCrozzoBranding();
  var pend = window.__crozzoIdentidadPending || {};
  var patch = {
    platform: {
      label: (document.getElementById('idPlatLabel') && document.getElementById('idPlatLabel').value) || 'BONA origen',
      emoji: (document.getElementById('idPlatEmoji') && document.getElementById('idPlatEmoji').value) || '🧾',
      loginEmoji: (document.getElementById('idPlatLoginEmoji') && document.getElementById('idPlatLoginEmoji').value) || '✨',
      dataUrl: pend.platform != null ? pend.platform : cur.platform.dataUrl,
      objectFit:
        document.getElementById('idPlatFit') && document.getElementById('idPlatFit').value === 'cover' ? 'cover' : 'contain'
    },
    tenant: {
      label: document.getElementById('idTenantLabel') ? document.getElementById('idTenantLabel').value.trim() : '',
      emoji: (document.getElementById('idTenantEmoji') && document.getElementById('idTenantEmoji').value) || '🏪',
      dataUrl: pend.tenant != null ? pend.tenant : cur.tenant.dataUrl,
      objectFit:
        document.getElementById('idTenantFit') && document.getElementById('idTenantFit').value === 'cover' ? 'cover' : 'contain'
    },
    sizes: {
      sidebar: {
        pw: crozzoIdentidadNum('idSzSbPw', 240, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        ph: crozzoIdentidadNum('idSzSbPh', 100, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        tw: crozzoIdentidadNum('idSzSbTw', 40, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        th: crozzoIdentidadNum('idSzSbTh', 40, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX)
      },
      header: {
        pw: crozzoIdentidadNum('idSzHdPw', 100, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        ph: crozzoIdentidadNum('idSzHdPh', 100, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        tw: crozzoIdentidadNum('idSzHdTw', 32, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        th: crozzoIdentidadNum('idSzHdTh', 32, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX)
      },
      login: {
        pw: crozzoIdentidadNum('idSzLgPw', 300, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        ph: crozzoIdentidadNum('idSzLgPh', 120, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        tw: crozzoIdentidadNum('idSzLgTw', 56, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX),
        th: crozzoIdentidadNum('idSzLgTh', 56, CROZZO_BRAND_SLOT_PX_MIN, CROZZO_BRAND_SLOT_PX_MAX)
      }
    },
    show: {
      sidebar: {
        platform: !!(document.getElementById('idShSbP') && document.getElementById('idShSbP').checked),
        tenant: false
      },
      header: {
        platform: !!(document.getElementById('idShHdP') && document.getElementById('idShHdP').checked),
        tenant: !!(document.getElementById('idShHdT') && document.getElementById('idShHdT').checked)
      },
      login: {
        platform: !!(document.getElementById('idShLgP') && document.getElementById('idShLgP').checked),
        tenant: !!(document.getElementById('idShLgT') && document.getElementById('idShLgT').checked)
      }
    },
    layout: {
      sidebarGap: crozzoIdentidadNum('idGapSb', 10, 0, CROZZO_BRAND_GAP_MAX),
      headerGap: crozzoIdentidadNum('idGapHd', 8, 0, CROZZO_BRAND_GAP_MAX),
      loginGap: crozzoIdentidadNum('idGapLg', 12, 0, CROZZO_BRAND_GAP_MAX)
    },
    motion: {
      enabled: !!(document.getElementById('idMotionOn') && document.getElementById('idMotionOn').checked),
      intensity: (document.getElementById('idMotionInt') && document.getElementById('idMotionInt').value) || 'high'
    },
    views: {
      sidebar: {
        platform: crozzoIdentidadReadViewFromForm('sidebar', 'platform'),
        tenant: crozzoIdentidadReadViewFromForm('sidebar', 'tenant')
      },
      header: {
        platform: crozzoIdentidadReadViewFromForm('header', 'platform'),
        tenant: crozzoIdentidadReadViewFromForm('header', 'tenant')
      },
      login: {
        platform: crozzoIdentidadReadViewFromForm('login', 'platform'),
        tenant: crozzoIdentidadReadViewFromForm('login', 'tenant')
      }
    }
  };
  var merged = crozzoSanitizeBrandingBundle(crozzoMergeIdentidad(cur, patch));
  localStorage.setItem(CROZZO_BRANDING_LS_KEY, JSON.stringify(merged));
  window.__crozzoIdentidadPending = { platform: null, tenant: null };
  applyCrozzoBrandingChrome();
  try {
    if (typeof crozzoScheduleTenantSnapshotPush === 'function') crozzoScheduleTenantSnapshotPush();
  } catch (_) {}
  var pf = document.getElementById('idPlatFile');
  var tf = document.getElementById('idTenantFile');
  if (pf) pf.value = '';
  if (tf) tf.value = '';
  if (typeof showToast === 'function') showToast('Identidad guardada', 'success');
  if (typeof config !== 'undefined' && config.addAudit) {
    try {
      config.addAudit('identidad_visual', 'Actualización de logos y chrome visual');
    } catch (e) {
      /* ignore */
    }
  }
  navigateTo('super-admin-identidad');
}
function crozzoIdentidadNum(id, def, min, max) {
  var el = document.getElementById(id);
  var n = el ? parseInt(el.value, 10) : def;
  if (isNaN(n)) n = def;
  return Math.min(max, Math.max(min, n));
}
function initSuperAdminIdentidad() {
  window.__crozzoIdentidadPending = window.__crozzoIdentidadPending || { platform: null, tenant: null };
  var root = document.getElementById('crozzoIdentidadRoot');
  if (root && !root._crozzoIdentidadPvBound) {
    root._crozzoIdentidadPvBound = true;
    var refreshPv = function () {
      if (typeof crozzoIdentidadRefreshPreview === 'function') crozzoIdentidadRefreshPreview();
    };
    root.addEventListener('input', refreshPv, false);
    root.addEventListener('change', refreshPv, false);
  }
  var pf = document.getElementById('idPlatFile');
  var tf = document.getElementById('idTenantFile');
  if (pf) {
    pf.addEventListener(
      'change',
      function () {
        var f = pf.files && pf.files[0];
        if (!f) return;
        crozzoImageFileToDataUrl(f, CROZZO_BRAND_IMAGE_MAX_SIDE, function (url, err) {
          if (!url) {
            if (typeof showToast === 'function') showToast('No se pudo leer la imagen', 'error');
            return;
          }
          window.__crozzoIdentidadPending.platform = url;
          var h = document.getElementById('idPlatFileHint');
          if (h) h.textContent = 'Listo para guardar: nueva imagen plataforma (~' + Math.round(url.length / 1024) + ' KB).';
          if (typeof showToast === 'function') showToast('Imagen plataforma lista; pulsa Guardar', 'success');
          if (typeof crozzoIdentidadRefreshPreview === 'function') crozzoIdentidadRefreshPreview();
        });
      },
      false
    );
  }
  if (tf) {
    tf.addEventListener(
      'change',
      function () {
        var f = tf.files && tf.files[0];
        if (!f) return;
        crozzoImageFileToDataUrl(f, CROZZO_BRAND_IMAGE_MAX_SIDE, function (url, err) {
          if (!url) {
            if (typeof showToast === 'function') showToast('No se pudo leer la imagen', 'error');
            return;
          }
          window.__crozzoIdentidadPending.tenant = url;
          var h = document.getElementById('idTenantFileHint');
          if (h) h.textContent = 'Listo para guardar: nueva imagen negocio (~' + Math.round(url.length / 1024) + ' KB).';
          if (typeof showToast === 'function') showToast('Imagen negocio lista; pulsa Guardar', 'success');
          if (typeof crozzoIdentidadRefreshPreview === 'function') crozzoIdentidadRefreshPreview();
        });
      },
      false
    );
  }
  if (root && !root._crozzoIdentidadRangeBound) {
    root._crozzoIdentidadRangeBound = true;
    root.querySelectorAll('.crozzo-identidad-range-num[data-range-for]').forEach(function (numEl) {
      var rangeId = numEl.getAttribute('data-range-for');
      var rangeEl = rangeId ? document.getElementById(rangeId) : null;
      if (!rangeEl) return;
      var syncFromRange = function () {
        numEl.value = rangeEl.value;
      };
      var syncFromNum = function () {
        var n = parseInt(numEl.value, 10);
        if (isNaN(n)) return;
        rangeEl.value = String(Math.min(parseInt(rangeEl.max, 10) || 200, Math.max(parseInt(rangeEl.min, 10) || 0, n)));
      };
      rangeEl.addEventListener('input', syncFromRange, false);
      numEl.addEventListener('change', syncFromNum, false);
    });
  }
  if (typeof crozzoIdentidadRefreshPreview === 'function') {
    setTimeout(crozzoIdentidadRefreshPreview, 0);
  }
}
