function crozzoCollectLocalBackupPayload() {
  const out = {
    meta: {
      v: 2,
      at: new Date().toISOString(),
      app: 'ProyectoPOS',
      note: 'pos_dian_config (sin secretos) + crozzo_* + CROZZO_*'
    },
    localStorage: {}
  };
  try {
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (!k) continue;
      if (k === 'pos_dian_config' || k.startsWith('crozzo_') || k.startsWith('CROZZO_')) {
        if (k === 'pos_dian_config') {
          try {
            const raw = localStorage.getItem(k);
            const cfg = raw ? JSON.parse(raw) : {};
            const red =
              window.CrozzoAuthSecurity && typeof CrozzoAuthSecurity.crozzoRedactConfigForBackup === 'function'
                ? CrozzoAuthSecurity.crozzoRedactConfigForBackup(cfg)
                : cfg;
            out.localStorage[k] = JSON.stringify(red);
          } catch (_) {
            out.localStorage[k] = localStorage.getItem(k);
          }
        } else {
          out.localStorage[k] = localStorage.getItem(k);
        }
      }
    }
  } catch (e) {
    console.warn('[backup] collect', e);
  }
  return out;
}
function crozzoExportLocalBackup() {
  try {
    const data = crozzoCollectLocalBackupPayload();
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `crozzo_backup_${new Date().toISOString().slice(0, 10)}.json`;
    a.click();
    URL.revokeObjectURL(a.href);
    if (typeof config !== 'undefined' && config.addAudit) {
      config.addAudit('backup_export', `Claves: ${Object.keys(data.localStorage).length}`);
    }
    showToast('Respaldo descargado', 'success');
  } catch (e) {
    console.error(e);
    showToast('No se pudo exportar', 'error');
  }
}
function crozzoImportLocalBackupFile(input) {
  const f = input && input.files && input.files[0];
  if (!f) return;
  const reader = new FileReader();
  reader.onload = () => {
    try {
      const data = JSON.parse(String(reader.result || '{}'));
      const keys = data.localStorage && typeof data.localStorage === 'object' ? data.localStorage : null;
      if (!keys || !Object.keys(keys).length) {
        showToast('JSON sin bloque localStorage', 'warning');
        return;
      }
      let n = 0;
      Object.entries(keys).forEach(([k, v]) => {
        if (v == null) return;
        if (
          k === 'pos_dian_config' ||
          k.startsWith('crozzo_') ||
          k.startsWith('CROZZO_')
        ) {
          localStorage.setItem(k, String(v));
          n++;
        }
      });
      if (typeof config !== 'undefined' && config.addAudit) {
        config.addAudit('backup_import', `Claves aplicadas: ${n}`);
      }
      showToast(`Importadas ${n} claves. Recargando…`, 'success');
      setTimeout(() => location.reload(), 800);
    } catch (err) {
      console.error(err);
      showToast('Archivo inválido', 'error');
    } finally {
      input.value = '';
    }
  };
  reader.readAsText(f);
}
window.crozzoExportLocalBackup = crozzoExportLocalBackup;
window.crozzoImportLocalBackupFile = crozzoImportLocalBackupFile;
