/**
 * PWA: manifest dinámico + prompt de instalación. SW solo en HTTPS/localhost (ver Crozzo_POS_sw.js).
 */
function crozzoPwaInit() {
  if (typeof document === 'undefined' || window.__crozzoPwaInitDone) return;
  window.__crozzoPwaInitDone = true;
  try {
    if (!document.getElementById('crozzo-web-manifest-link')) {
      const page = (location.pathname && /\.html$/i.test(location.pathname))
        ? './' + decodeURIComponent(location.pathname.split('/').pop() || '')
        : './';
      const iconSvg =
        'data:image/svg+xml,' +
        encodeURIComponent(
          "<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'><rect fill='%231d4ed8' width='100' height='100' rx='16'/><text x='50' y='62' text-anchor='middle' font-size='52'>🧾</text></svg>"
        );
      const manifest = {
        name: 'Proyecto · Sistema POS',
        short_name: 'Proyecto',
        start_url: page,
        scope: './',
        display: 'standalone',
        background_color: '#0b1220',
        theme_color: '#2563eb',
        icons: [{ src: iconSvg, sizes: '192x192', type: 'image/svg+xml' }]
      };
      const link = document.createElement('link');
      link.id = 'crozzo-web-manifest-link';
      link.rel = 'manifest';
      link.href = URL.createObjectURL(new Blob([JSON.stringify(manifest)], { type: 'application/manifest+json' }));
      document.head.appendChild(link);
    }
  } catch (e) {
    console.warn('[pwa] manifest', e);
  }
  let deferredPrompt = null;
  window.addEventListener('beforeinstallprompt', function (e) {
    e.preventDefault();
    deferredPrompt = e;
    const b = document.getElementById('crozzoPwaInstallBanner');
    if (b) {
      b.removeAttribute('hidden');
      b.classList.add('crozzo-pwa-shown');
    }
  });
  window.addEventListener('appinstalled', function () {
    deferredPrompt = null;
    const b = document.getElementById('crozzoPwaInstallBanner');
    if (b) {
      b.setAttribute('hidden', '');
      b.classList.remove('crozzo-pwa-shown');
    }
    if (typeof showToast === 'function') showToast('Aplicación instalada correctamente', 'success');
  });
  document.getElementById('crozzoPwaInstallBtn')?.addEventListener('click', async function () {
    if (!deferredPrompt) {
      if (typeof showToast === 'function') {
        showToast('Instalación no disponible (HTTPS o navegador compatible).', 'info');
      }
      return;
    }
    try {
      await deferredPrompt.prompt();
      await deferredPrompt.userChoice;
    } catch (err) {
      console.warn('[pwa] prompt', err);
    }
    deferredPrompt = null;
    const b = document.getElementById('crozzoPwaInstallBanner');
    if (b) {
      b.setAttribute('hidden', '');
      b.classList.remove('crozzo-pwa-shown');
    }
  });
  document.getElementById('crozzoPwaDismissBtn')?.addEventListener('click', function () {
    deferredPrompt = null;
    const b = document.getElementById('crozzoPwaInstallBanner');
    if (b) {
      b.setAttribute('hidden', '');
      b.classList.remove('crozzo-pwa-shown');
    }
  });
  /* Service Worker deshabilitado: no se usa en Tauri ni en dev localhost:1420 (Crozzo_POS_sw.js) */
}
/**
 * Checklist “listo para producción” alineado con pos_dian_config.
 */
function crozzoRunProductionReadiness() {
  const out = document.getElementById('crozzo-readiness-out');
  if (!out) return;
  const rows = [];
  function row(st, title, sub) {
    const ic = st === 'ok' ? '✅' : st === 'warn' ? '⚠️' : '🚫';
    rows.push(
      '<div class="crozzo-readiness-row ' +
        st +
        '"><span aria-hidden="true">' +
        ic +
        '</span><div><strong>' +
        title +
        '</strong><div class="form-hint">' +
        (sub ? String(sub).replace(/</g, '&lt;') : '') +
        '</div></div></div>'
    );
  }
  try {
    const live = typeof config !== 'undefined' && config.canGoLive ? config.canGoLive() : { valid: false, missing: ['config'] };
    row(
      live.valid ? 'ok' : 'warn',
      'Facturación electrónica (canGoLive)',
      live.valid ? 'Requisitos mínimos completos' : 'Falta: ' + (live.missing || []).join(', ')
    );
  } catch (e) {
    row('err', 'canGoLive', e && e.message);
  }
  const modo = typeof config !== 'undefined' && config.getOperacionModo ? config.getOperacionModo() : '';
  row(
    modo === 'electronic' ? 'ok' : 'warn',
    'Modo fiscal',
    modo === 'electronic' ? 'Electrónico activo' : 'Actual: ' + modo + ' (use Modo de operación para DIAN real)'
  );
  const cert = typeof config !== 'undefined' && config.getCertificado ? config.getCertificado() : {};
  row(
    cert.encrypted ? 'ok' : 'warn',
    'Certificado .p12',
    cert.encrypted
      ? (cert.p12Sha256
          ? 'Huella SHA-256 del archivo: ' + String(cert.p12Sha256).slice(0, 14) + '…'
          : 'Cargado (vuelva a guardar certificado para registrar huella)')
      : 'Sin certificado en configuración'
  );
  row(
    navigator.mediaDevices && typeof navigator.mediaDevices.getUserMedia === 'function' ? 'ok' : 'warn',
    'Cámara / QR (emparejamiento)',
    'Flujo nativo: escaneo en vivo + foto + pegar JSON (mismo módulo de emparejamiento)'
  );
  const pwaCtx = location.protocol === 'https:' || location.hostname === 'localhost' || location.hostname === '127.0.0.1';
  row(
    pwaCtx ? 'ok' : 'warn',
    'PWA / Service Worker',
    pwaCtx
      ? 'SW opcional: service worker junto a este HTML'
      : 'En file:// el SW no se registra (esperado). Use HTTPS para instalación y SW.'
  );
  row(typeof showToast === 'function' ? 'ok' : 'warn', 'Notificaciones', 'showToast unificado (#toastContainer)');
  out.innerHTML = '<div class="crozzo-readiness-list">' + rows.join('') + '</div>';
  if (typeof showToast === 'function') showToast('Checklist actualizado', 'info');
}
window.crozzoPwaInit = crozzoPwaInit;
window.crozzoRunProductionReadiness = crozzoRunProductionReadiness;
function crozzoExportAuditoriaCsv() {
  try {
    const logs =
      typeof config !== 'undefined' && config.config && Array.isArray(config.config.auditoria)
        ? config.config.auditoria.filter(l => !l.synthetic)
        : [];
    const cols = ['timestamp', 'user', 'action', 'details', 'modo', 'prevHash', 'chainHash'];
    const esc = (v) => {
      const s = String(v == null ? '' : v).replace(/"/g, '""');
      return `"${s}"`;
    };
    const lines = [cols.join(',')].concat(logs.map((log) => cols.map((c) => esc(log[c])).join(',')));
    const blob = new Blob([lines.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'crozzo_auditoria_' + new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-') + '.csv';
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(a.href);
    if (typeof showToast === 'function') showToast('CSV de auditoría descargado', 'success');
  } catch (_) {
    if (typeof showToast === 'function') showToast('No se pudo exportar la auditoría', 'error');
  }
}
window.crozzoExportAuditoriaCsv = crozzoExportAuditoriaCsv;
